SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A proton moving with velocity v enters a uniform magnetic field B perpendicular to its direction of motion. The path followed by the proton is:", "explanation": "When a charged particle enters a magnetic field perpendicular to its velocity, the magnetic force F = qv Г— B acts as a centripetal force. Since this force is always perpendicular to the velocity, it changes the direction but not the speed of the particle. This results in uniform circular motion. The radius of the circle is r = mv/(qB).", "correct_answer": "C", "concept_tags": ["circular-motion", "lorentz-force", "charged-particle-in-B"], "payload": {"question_id": "cuet-phy-mag-force-01", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "A straight line", "is_correct": false}, {"key": "B", "text": "A parabolic path", "is_correct": false}, {"key": "C", "text": "A circular path", "is_correct": true}, {"key": "D", "text": "A helical path", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A straight line would occur only if the velocity were parallel to B (zero force). Here v is perpendicular to B.", "misconception": "Thinking magnetic force does not deflect the particle"}, {"option_key": "B", "hint": "A parabolic path occurs under a constant force (like gravity). The magnetic force changes direction continuously, unlike gravity.", "misconception": "Confusing magnetic force with gravitational force"}, {"option_key": "D", "hint": "A helical path requires a velocity component along B. Since v is entirely perpendicular to B, the path is circular, not helical.", "misconception": "Assuming helical motion without a parallel velocity component"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The work done by a magnetic force on a charged particle moving in a magnetic field is:", "explanation": "The magnetic force F = qv Г— B is always perpendicular to the velocity of the charged particle. Since work done W = F В· ds = F В· v dt, and F is perpendicular to v, the dot product F В· v = 0. Hence, the magnetic force does no work on a moving charge. It can only change the direction of velocity, not its magnitude.", "correct_answer": "C", "concept_tags": ["work-done", "magnetic-force", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-02", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Positive", "is_correct": false}, {"key": "B", "text": "Negative", "is_correct": false}, {"key": "C", "text": "Always zero", "is_correct": true}, {"key": "D", "text": "Depends on the magnitude of charge", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Magnetic force is always perpendicular to velocity. A perpendicular force cannot increase the kinetic energy or do positive work.", "misconception": "Assuming any force that acts on a moving particle does work"}, {"option_key": "B", "hint": "Negative work would slow down the particle. But the speed of a charged particle in a pure magnetic field remains constant.", "misconception": "Confusing magnetic force with a drag or resistive force"}, {"option_key": "D", "hint": "Regardless of the magnitude of charge, the magnetic force is always perpendicular to displacement, so work is always zero.", "misconception": "Thinking work depends on charge magnitude alone"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A straight conductor of length 0.5 m carrying a current of 2 A is placed perpendicular to a uniform magnetic field of 0.4 T. The force experienced by the conductor is:", "explanation": "Using F = BIL sinОё, where B = 0.4 T, I = 2 A, L = 0.5 m, and Оё = 90В° (perpendicular). F = 0.4 Г— 2 Г— 0.5 Г— sin90В° = 0.4 Г— 2 Г— 0.5 Г— 1 = 0.4 N.", "correct_answer": "A", "concept_tags": ["force-on-conductor", "BIL-formula", "perpendicular-field"], "payload": {"question_id": "cuet-phy-mag-force-03", "subtopic": "force on current-carrying conductor (F=BIL sinОё)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.4 N", "is_correct": true}, {"key": "B", "text": "0.2 N", "is_correct": false}, {"key": "C", "text": "0.8 N", "is_correct": false}, {"key": "D", "text": "0.1 N", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This would result from using sinОё = 0.5 (i.e., Оё = 30В°), but the conductor is perpendicular to the field so sinОё = 1.", "misconception": "Using wrong angle in F = BIL sinОё"}, {"option_key": "C", "hint": "This is double the correct answer. Check that you are not multiplying any quantity twice.", "misconception": "Arithmetic error in multiplication"}, {"option_key": "D", "hint": "This is one-fourth of the correct value. Verify all substituted values: B = 0.4, I = 2, L = 0.5.", "misconception": "Incorrect substitution of given values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A charged particle moving with velocity v enters a uniform magnetic field B perpendicular to its velocity. The magnetic force on the particle is:", "explanation": "The magnetic force on a moving charged particle is given by F = qv Г— B. When the velocity is perpendicular to the magnetic field (Оё = 90В°), sin 90В° = 1, so F = qvB. This is the maximum force the magnetic field can exert on the charge.", "correct_answer": "A", "concept_tags": ["lorentz-force", "magnetic-force", "moving-charge"], "payload": {"question_id": "cuet-phy-mag-force-04", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "qvB", "is_correct": true}, {"key": "B", "text": "qvB/2", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "qv/B", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The factor of 1/2 does not appear in the Lorentz force formula. F = qvB sinОё has no such coefficient.", "misconception": "Confusing with kinetic energy formula which has a 1/2 factor"}, {"option_key": "C", "hint": "Force is zero only when the charge moves parallel to B (Оё = 0В°). Here the motion is perpendicular to B, so sinОё = 1.", "misconception": "Confusing perpendicular and parallel motion relative to B"}, {"option_key": "D", "hint": "Dimensionally, qv/B gives CВ·m/(sВ·T) which does not have units of force. The correct formula has B in the numerator.", "misconception": "Incorrectly placing B in the denominator"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two long parallel conductors carry currents in the same direction. The force between them is:", "explanation": "When two parallel conductors carry currents in the same direction, the magnetic field produced by one conductor at the location of the other results in an attractive force between them. This can be verified using the right-hand rule: the field from one wire at the other wire''s location creates a force directed toward the first wire. Currents in opposite directions repel each other.", "correct_answer": "A", "concept_tags": ["parallel-conductors", "force-between-conductors", "attractive-force"], "payload": {"question_id": "cuet-phy-mag-force-05", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "Attractive", "is_correct": true}, {"key": "B", "text": "Repulsive", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "Attractive or repulsive depending on the magnitude of currents", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Repulsive force occurs between parallel conductors carrying currents in opposite directions. Same-direction currents always attract.", "misconception": "Confusing same-direction and opposite-direction current rules"}, {"option_key": "C", "hint": "Two current-carrying conductors always exert a force on each other. The force is zero only when one of the currents is zero.", "misconception": "Thinking parallel conductors do not interact magnetically"}, {"option_key": "D", "hint": "The nature of the force (attractive/repulsive) depends only on the relative direction of currents, not on their magnitudes.", "misconception": "Confusing the nature of force with its magnitude"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A proton moves parallel to a uniform magnetic field. The force acting on the proton is:", "explanation": "The magnetic force on a charged particle is F = qvB sinОё. When the particle moves parallel to B, the angle Оё = 0В°, and sin 0В° = 0. Therefore, F = 0. A magnetic field exerts no force on a charge moving along the field direction.", "correct_answer": "B", "concept_tags": ["magnetic-force", "parallel-motion", "zero-force"], "payload": {"question_id": "cuet-phy-mag-force-06", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "qvB", "is_correct": false}, {"key": "B", "text": "Zero", "is_correct": true}, {"key": "C", "text": "qvB/2", "is_correct": false}, {"key": "D", "text": "qB/v", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "F = qvB applies only when v is perpendicular to B (Оё = 90В°). Here the motion is parallel, so sinОё = 0.", "misconception": "Ignoring the sinОё dependence in the Lorentz force"}, {"option_key": "C", "hint": "There is no 1/2 factor in the force formula, and regardless the force is zero when velocity is parallel to B.", "misconception": null}, {"option_key": "D", "hint": "This expression is dimensionally incorrect for force and does not correspond to any known formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a velocity selector, electric and magnetic fields are applied perpendicular to each other and to the velocity of charged particles. A particle passes through undeflected when:", "explanation": "In a velocity selector, the electric force qE and the magnetic force qvB act in opposite directions on the charged particle. For the particle to pass undeflected, these forces must balance: qE = qvB, giving v = E/B. This condition is independent of the charge and mass of the particle, so only particles with velocity v = E/B pass through straight.", "correct_answer": "C", "concept_tags": ["velocity-selector", "electric-magnetic-balance", "undeflected-motion"], "payload": {"question_id": "cuet-phy-mag-force-07", "subtopic": "velocity selector", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "v = B/E", "is_correct": false}, {"key": "B", "text": "v = EB", "is_correct": false}, {"key": "C", "text": "v = E/B", "is_correct": true}, {"key": "D", "text": "v = EВІ/B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the inverse of the correct relation. From qE = qvB, solve for v: v = E/B, not B/E.", "misconception": "Inverting the ratio when solving qE = qvB"}, {"option_key": "B", "hint": "Check dimensions: EB has units of VВ·T/m, which is not velocity. v = E/B has units (V/m)/(T) = m/s.", "misconception": "Multiplying instead of dividing E and B"}, {"option_key": "D", "hint": "This has incorrect dimensions. The balance condition qE = qvB gives a linear relation between v, E, and B.", "misconception": "Introducing an incorrect power of E"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron (charge e, mass m) and a proton (charge e, mass M) enter a uniform magnetic field perpendicularly with the same kinetic energy. The ratio of radii of their circular paths (rв‚‘/rв‚љ) is:", "explanation": "The radius of circular motion in a magnetic field is r = mv/(eB). Since kinetic energy K = ВЅmvВІ, we get v = в€љ(2K/m), so r = mв€љ(2K/m)/(eB) = в€љ(2mK)/(eB). Therefore rв‚‘/rв‚љ = в€љ(m/M). Since the electron mass m is much smaller than proton mass M, the electron follows a much smaller circle.", "correct_answer": "C", "concept_tags": ["radius-ratio", "kinetic-energy", "electron", "proton", "circular-motion"], "payload": {"question_id": "cuet-phy-mag-force-08", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "m/M", "is_correct": false}, {"key": "B", "text": "M/m", "is_correct": false}, {"key": "C", "text": "в€љ(m/M)", "is_correct": true}, {"key": "D", "text": "в€љ(M/m)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the ratio if r were directly proportional to mass (at same velocity). But at same kinetic energy, r = в€љ(2mK)/(eB), giving a square-root dependence.", "misconception": "Using r = mv/(qB) without converting velocity in terms of kinetic energy"}, {"option_key": "B", "hint": "M/m > 1 would mean the electron has a larger radius than the proton, which contradicts the fact that the lighter particle has a smaller radius at equal KE.", "misconception": "Inverting the mass ratio"}, {"option_key": "D", "hint": "в€љ(M/m) > 1 would imply rв‚‘ > rв‚љ. Since the electron is lighter, it has less momentum at the same KE and hence a smaller radius.", "misconception": "Confusing which particle has the larger radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a velocity selector, a charged particle passes undeflected when:", "explanation": "In a velocity selector, crossed electric (E) and magnetic (B) fields are applied. The electric force qE and the magnetic force qvB act in opposite directions. The particle passes undeflected when these forces balance: qE = qvB, giving v = E/B. This condition is independent of the charge and mass of the particle.", "correct_answer": "C", "concept_tags": ["velocity-selector", "electric-field", "magnetic-field", "undeflected"], "payload": {"question_id": "cuet-phy-mag-force-09", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "v = B/E", "is_correct": false}, {"key": "B", "text": "v = EB", "is_correct": false}, {"key": "C", "text": "v = E/B", "is_correct": true}, {"key": "D", "text": "v = EВІ/B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "B/E is the inverse of the correct answer. From qE = qvB, solving for v gives v = E/B, not B/E.", "misconception": "Inverting the ratio while solving qE = qvB"}, {"option_key": "B", "hint": "EB is dimensionally incorrect for velocity. E has units V/m and B has units T, so EB would have units VВ·T/m, not m/s.", "misconception": "Incorrectly combining E and B"}, {"option_key": "D", "hint": "EВІ/B does not follow from balancing electric and magnetic forces. The correct derivation gives v = E/B.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charged particle of mass m and charge q moves in a circular orbit of radius r in a magnetic field B. The kinetic energy of the particle is:", "explanation": "For circular motion in a magnetic field: qvB = mvВІ/r, giving v = qBr/m. The kinetic energy is KE = ВЅmvВІ = ВЅm(qBr/m)ВІ = qВІBВІrВІ/(2m). This shows that the kinetic energy depends on the square of the charge, field, and radius, and inversely on the mass.", "correct_answer": "D", "concept_tags": ["circular-motion", "kinetic-energy", "radius-momentum-relation"], "payload": {"question_id": "cuet-phy-mag-force-10", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "qBr/m", "is_correct": false}, {"key": "B", "text": "qВІBВІr/(2m)", "is_correct": false}, {"key": "C", "text": "qBВІrВІ/(2m)", "is_correct": false}, {"key": "D", "text": "qВІBВІrВІ/(2m)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This has dimensions of velocity, not energy. Kinetic energy must have dimensions of kgВ·mВІ/sВІ.", "misconception": "Confusing velocity with kinetic energy"}, {"option_key": "B", "hint": "Check the power of r. From v = qBr/m, vВІ involves rВІ, not r.", "misconception": "Missing a factor of r in the derivation"}, {"option_key": "C", "hint": "Check the power of q. From v = qBr/m, vВІ involves qВІ, not q.", "misconception": "Missing a factor of q in the derivation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a cyclotron, a proton is accelerated to high speeds. The time period of revolution of the proton in the magnetic field is independent of:", "explanation": "In a cyclotron, the time period T = 2ПЂm/(qB). This expression shows that T depends on the mass m, charge q, and magnetic field B, but is independent of the speed (or kinetic energy) of the particle and the radius of its circular path. This independence of speed from the time period is the fundamental principle that allows the cyclotron to work with a fixed-frequency oscillating electric field.", "correct_answer": "A", "concept_tags": ["cyclotron", "time-period", "frequency-independence"], "payload": {"question_id": "cuet-phy-mag-force-11", "subtopic": "cyclotron", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Speed and radius of the circular path", "is_correct": true}, {"key": "B", "text": "Mass of the particle", "is_correct": false}, {"key": "C", "text": "Charge of the particle", "is_correct": false}, {"key": "D", "text": "Magnetic field strength", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "T = 2ПЂm/(qB) explicitly contains m in the numerator. Changing the mass changes the time period.", "misconception": "Thinking mass does not affect the cyclotron frequency"}, {"option_key": "C", "hint": "T = 2ПЂm/(qB) contains q in the denominator. Changing the charge changes the time period.", "misconception": "Thinking charge does not affect the cyclotron frequency"}, {"option_key": "D", "hint": "T = 2ПЂm/(qB) contains B in the denominator. A stronger field means a shorter time period.", "misconception": "Thinking the magnetic field does not affect the time period"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A straight conductor of length 0.5 m carrying a current of 2 A is placed in a uniform magnetic field of 0.4 T at an angle of 30В° to the field. The force on the conductor is:", "explanation": "The force on a current-carrying conductor in a magnetic field is F = BIL sinОё. Substituting the given values: F = 0.4 Г— 2 Г— 0.5 Г— sin 30В° = 0.4 Г— 2 Г— 0.5 Г— 0.5 = 0.2 N.", "correct_answer": "D", "concept_tags": ["force-on-conductor", "current-carrying-conductor", "magnetic-field", "numerical"], "payload": {"question_id": "cuet-phy-mag-force-12", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.4 N", "is_correct": false}, {"key": "B", "text": "0.1 N", "is_correct": false}, {"key": "C", "text": "0.8 N", "is_correct": false}, {"key": "D", "text": "0.2 N", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.4 N would be the answer if sinОё = 1 (Оё = 90В°). Here Оё = 30В°, so sin 30В° = 0.5 must be included.", "misconception": "Forgetting the sinОё factor when the conductor is not perpendicular to B"}, {"option_key": "B", "hint": "0.1 N would result from using sin 30В° twice or an arithmetic error. Check: F = 0.4 Г— 2 Г— 0.5 Г— 0.5 = 0.2 N.", "misconception": "Arithmetic error in multiplication"}, {"option_key": "C", "hint": "0.8 N would result from ignoring sin 30В° and also doubling the result. F = BIL sinОё, not 2BIL.", "misconception": "Using an incorrect formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charged particle moves in a helical path in a uniform magnetic field. This happens when the velocity of the particle:", "explanation": "When a charged particle enters a magnetic field with its velocity at an angle to the field (neither parallel nor perpendicular), the velocity component perpendicular to B causes circular motion while the component parallel to B remains unaffected. The combination of circular motion and uniform linear motion along B produces a helical (spiral) path.", "correct_answer": "D", "concept_tags": ["helical-motion", "velocity-components", "magnetic-field"], "payload": {"question_id": "cuet-phy-mag-force-13", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Is perpendicular to B", "is_correct": false}, {"key": "B", "text": "Is parallel to B", "is_correct": false}, {"key": "C", "text": "Is zero", "is_correct": false}, {"key": "D", "text": "Has components both parallel and perpendicular to B", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "When velocity is purely perpendicular to B, the particle follows a circular path, not a helical one.", "misconception": "Confusing circular and helical paths"}, {"option_key": "B", "hint": "When velocity is parallel to B, there is no magnetic force and the particle moves in a straight line.", "misconception": "Not recognizing that parallel motion produces zero force"}, {"option_key": "C", "hint": "If velocity is zero, there is no motion at all and hence no path of any kind.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two long parallel wires separated by a distance of 0.1 m carry currents of 5 A and 10 A in the same direction. The force per unit length between them is: (Ојв‚Ђ = 4ПЂ Г— 10вЃ»вЃ· TВ·m/A)", "explanation": "The force per unit length between two parallel current-carrying wires is F/L = Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd). Substituting: F/L = (4ПЂ Г— 10вЃ»вЃ· Г— 5 Г— 10)/(2ПЂ Г— 0.1) = (4ПЂ Г— 10вЃ»вЃ· Г— 50)/(0.2ПЂ) = (200ПЂ Г— 10вЃ»вЃ·)/(0.2ПЂ) = 1000 Г— 10вЃ»вЃ· = 10вЃ»вЃґ N/m = 1 Г— 10вЃ»вЃґ N/m. Since the currents are in the same direction, the force is attractive.", "correct_answer": "B", "concept_tags": ["parallel-currents", "force-per-unit-length", "attractive-force"], "payload": {"question_id": "cuet-phy-mag-force-14", "subtopic": "force between parallel currents", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "2 Г— 10вЃ»вЃґ N/m, repulsive", "is_correct": false}, {"key": "B", "text": "1 Г— 10вЃ»вЃґ N/m, attractive", "is_correct": true}, {"key": "C", "text": "1 Г— 10вЃ»вЃґ N/m, repulsive", "is_correct": false}, {"key": "D", "text": "5 Г— 10вЃ»вЃµ N/m, attractive", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Check your calculation. The factor 2ПЂ in the denominator should give 10вЃ»вЃґ, not 2 Г— 10вЃ»вЃґ. Also, same-direction currents attract.", "misconception": "Error in simplifying the 2ПЂ factor"}, {"option_key": "C", "hint": "The magnitude is correct, but same-direction currents attract each other, they do not repel.", "misconception": "Confusing the direction of force between parallel currents"}, {"option_key": "D", "hint": "This is half the correct value. Verify your substitution of Iв‚Ѓ and Iв‚‚ in the formula.", "misconception": "Using incorrect current values in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A proton (mass 1.67 Г— 10вЃ»ВІвЃ· kg) moves with a speed of 5 Г— 10вЃ¶ m/s perpendicular to a magnetic field of 0.5 T. The radius of the circular path described by the proton is (charge of proton = 1.6 Г— 10вЃ»В№вЃ№ C):", "explanation": "When a charged particle moves perpendicular to a magnetic field, it follows a circular path. The radius is given by r = mv/(qB). Substituting: r = (1.67 Г— 10вЃ»ВІвЃ· Г— 5 Г— 10вЃ¶) / (1.6 Г— 10вЃ»В№вЃ№ Г— 0.5) = (8.35 Г— 10вЃ»ВІВ№) / (8.0 Г— 10вЃ»ВІвЃ°) = 0.104 m в‰€ 0.1 m.", "correct_answer": "B", "concept_tags": ["circular-motion", "radius-of-path", "proton", "magnetic-field"], "payload": {"question_id": "cuet-phy-mag-force-15", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 m", "is_correct": false}, {"key": "B", "text": "0.1 m", "is_correct": true}, {"key": "C", "text": "1.0 m", "is_correct": false}, {"key": "D", "text": "0.05 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Re-check the calculation: r = mv/(qB) = (1.67 Г— 10вЃ»ВІвЃ· Г— 5 Г— 10вЃ¶)/(1.6 Г— 10вЃ»В№вЃ№ Г— 0.5) в‰€ 0.1 m.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "C", "hint": "1.0 m is ten times the correct answer. Ensure proper handling of exponents in the numerator and denominator.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "D", "hint": "0.05 m results from an incorrect factor of 2. The formula r = mv/(qB) does not include any additional numerical factor.", "misconception": "Introducing an extraneous factor in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force per unit length between two long parallel conductors carrying currents Iв‚Ѓ and Iв‚‚ separated by a distance d is given by:", "explanation": "The magnetic field produced by conductor 1 at the location of conductor 2 is Bв‚Ѓ = Ојв‚ЂIв‚Ѓ/(2ПЂd). The force per unit length on conductor 2 is F/L = Bв‚ЃIв‚‚ = Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd). This expression is fundamental and is used to define the SI unit of current (ampere).", "correct_answer": "B", "concept_tags": ["force-per-unit-length", "parallel-conductors", "ampere-definition"], "payload": {"question_id": "cuet-phy-mag-force-16", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "Ојв‚ЂIв‚ЃIв‚‚/(4ПЂd)", "is_correct": false}, {"key": "B", "text": "Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd)", "is_correct": true}, {"key": "C", "text": "Ојв‚ЂIв‚ЃIв‚‚/(2ПЂdВІ)", "is_correct": false}, {"key": "D", "text": "Ојв‚ЂIв‚ЃIв‚‚d/(2ПЂ)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The factor is 2ПЂ in the denominator, not 4ПЂ. The field of a long wire is B = Ојв‚ЂI/(2ПЂd), and force/length = BIв‚‚ = Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd).", "misconception": "Confusing 2ПЂ (Biot-Savart for infinite wire) with 4ПЂ (Coulomb''s law constant)"}, {"option_key": "C", "hint": "The distance d appears to the first power, not squared. This is not an inverse-square law like Coulomb''s law.", "misconception": "Incorrectly applying inverse-square law to magnetic force between wires"}, {"option_key": "D", "hint": "Having d in the numerator would mean force increases with distance, which is physically incorrect. Force decreases as conductors are moved apart.", "misconception": "Placing d in the wrong part of the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An alpha particle (charge 2e, mass 4mв‚љ) and a proton (charge e, mass mв‚љ) are accelerated from rest through the same potential difference and then enter a uniform magnetic field perpendicular to their velocity. The ratio of the radii of their circular paths (rО±/rв‚љ) is:", "explanation": "After acceleration through potential difference V, kinetic energy K = qV. So KО± = 2eV and Kв‚љ = eV. The radius of circular motion is r = в€љ(2mK)/(qB). For alpha particle: rО± = в€љ(2 Г— 4mв‚љ Г— 2eV)/(2eB) = в€љ(16mв‚љeV)/(2eB) = 4в€љ(mв‚љeV)/(2eB). For proton: rв‚љ = в€љ(2mв‚љeV)/(eB) = в€љ(2mв‚љeV)/(eB). Therefore rО±/rв‚љ = [4в€љ(mв‚љeV)/(2eB)] / [в€љ(2mв‚љeV)/(eB)] = [4/(2)] Г— [1/в€љ2] = 2/в€љ2 = в€љ2 = 1:1 Г— в€љ2. So rО±/rв‚љ = в€љ2.", "correct_answer": "C", "concept_tags": ["alpha-particle", "proton", "radius-ratio", "potential-difference", "circular-motion"], "payload": {"question_id": "cuet-phy-mag-force-17", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "1:1", "is_correct": false}, {"key": "B", "text": "2:1", "is_correct": false}, {"key": "C", "text": "в€љ2 : 1", "is_correct": true}, {"key": "D", "text": "1 : в€љ2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1:1 would require identical r values. Since the alpha particle has different mass and charge, r = в€љ(2mK)/(qB) with K = qV gives different radii.", "misconception": "Assuming equal radii for particles accelerated through same potential"}, {"option_key": "B", "hint": "2:1 would result from r в€ќ m/q without properly accounting for the velocity gained through the potential difference.", "misconception": "Not correctly relating kinetic energy to the potential difference for different charges"}, {"option_key": "D", "hint": "1:в€љ2 is the inverse of the correct ratio. The alpha particle, with greater momentum, has the larger radius.", "misconception": "Inverting the ratio of radii"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton and an alpha particle (charge 2e, mass 4mв‚љ) enter a uniform magnetic field perpendicular to their velocities. If both have the same kinetic energy, the ratio of the radii of their circular paths (rв‚љ/rО±) is:", "explanation": "The radius of circular motion is r = mv/(qB). Since KE = ВЅmvВІ, we get v = в€љ(2KE/m), so r = mв€љ(2KE/m)/(qB) = в€љ(2mKE)/(qB). For the proton: rв‚љ = в€љ(2mв‚љKE)/(eB). For the alpha particle: rО± = в€љ(2 Г— 4mв‚љ Г— KE)/(2eB) = 2в€љ(2mв‚љKE)/(2eB) = в€љ(2mв‚љKE)/(eB). Therefore rв‚љ/rО± = [в€љ(2mв‚љKE)/(eB)] / [в€љ(2mв‚љKE)/(eB)] = 1. The ratio is 1:1.", "correct_answer": "D", "concept_tags": ["radius-ratio", "kinetic-energy", "proton-alpha-comparison"], "payload": {"question_id": "cuet-phy-mag-force-18", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 2", "is_correct": false}, {"key": "B", "text": "2 : 1", "is_correct": false}, {"key": "C", "text": "1 : в€љ2", "is_correct": false}, {"key": "D", "text": "1 : 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would be correct if both had the same momentum, not the same kinetic energy. With equal KE, r = в€љ(2mKE)/(qB).", "misconception": "Confusing equal kinetic energy with equal momentum"}, {"option_key": "B", "hint": "This is the inverse of option A. Neither is correct for equal kinetic energy conditions.", "misconception": "Inverting the ratio while still using the momentum formula"}, {"option_key": "C", "hint": "This would arise from an error in the mass or charge ratio. For an alpha particle, m = 4mв‚љ and q = 2e; в€љ(4mв‚љ)/(2e) = в€љ(mв‚љ)/e.", "misconception": "Algebraic error in evaluating в€љm/q for the alpha particle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A charged particle enters a region where a uniform magnetic field B and a uniform electric field E are both present and mutually perpendicular. If the particle has charge q, mass m, and enters with velocity v = E/B perpendicular to both fields, but the electric field is suddenly switched off, the radius of the resulting circular path is:", "explanation": "Initially the particle moves undeflected with v = E/B (velocity selector condition). When the electric field is switched off, only the magnetic force acts. The particle moves in a circle with radius r = mv/(qB). Substituting v = E/B: r = m(E/B)/(qB) = mE/(qBВІ). This radius depends on the mass-to-charge ratio and the fields.", "correct_answer": "D", "concept_tags": ["velocity-selector", "circular-motion", "radius-formula"], "payload": {"question_id": "cuet-phy-mag-force-19", "subtopic": "velocity selector", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "mE/(qB)", "is_correct": false}, {"key": "B", "text": "mB/(qE)", "is_correct": false}, {"key": "C", "text": "mEВІ/(qBВІ)", "is_correct": false}, {"key": "D", "text": "mE/(qBВІ)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Check dimensions: mE/(qB) has units of kgВ·(V/m)/(CВ·T) = kgВ·m/sВІ Г— s/(C) which is not length. You need r = mv/(qB) with v = E/B.", "misconception": "Forgetting to substitute v = E/B into the radius formula"}, {"option_key": "B", "hint": "This inverts E and B. The velocity is E/B, not B/E, so the radius involves E in the numerator and BВІ in the denominator.", "misconception": "Inverting the velocity selector relation"}, {"option_key": "C", "hint": "The radius is r = mv/(qB) = m(E/B)/(qB) = mE/(qBВІ). There is no EВІ term.", "misconception": "Squaring E instead of B in the substitution"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of length L is bent into a semicircular loop and carries a current I. It is placed in a uniform magnetic field B directed perpendicular to the plane of the loop. The net force on the semicircular wire is:", "explanation": "For a curved wire in a uniform magnetic field, the net force equals the force on a straight wire connecting the two ends of the curve. The semicircular wire of length L has radius r = L/ПЂ. The straight-line distance between the two ends (the diameter) is 2r = 2L/ПЂ. Therefore, the net force is F = BI Г— (2L/ПЂ) = 2BIL/ПЂ. The direction follows from F = IL Г— B for the equivalent straight conductor.", "correct_answer": "A", "concept_tags": ["semicircular-loop", "net-force", "uniform-field", "equivalent-straight-wire"], "payload": {"question_id": "cuet-phy-mag-force-20", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "2BIL/ПЂ", "is_correct": true}, {"key": "B", "text": "BIL", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "ПЂBIL", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "BIL would be the force if the entire wire length L were straight and perpendicular to B. But for a semicircle, the effective length is the chord (diameter) = 2L/ПЂ.", "misconception": "Using the arc length instead of the chord length for net force"}, {"option_key": "C", "hint": "Zero net force applies to a complete closed loop in a uniform field. A semicircle is not a closed loop, so the net force is not zero.", "misconception": "Confusing semicircular wire with a complete loop"}, {"option_key": "D", "hint": "ПЂBIL greatly overestimates the force. The effective straight-line length is 2L/ПЂ, which is shorter than L, not longer.", "misconception": "Using an incorrect geometric relationship"}]}}]'::jsonb, 'deploy-2026-03-05-b02');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a straight current-carrying conductor placed in a uniform magnetic field directed into the page. The current flows from left to right. Using Fleming''s left-hand rule, the force on the conductor is directed:", "explanation": "Using Fleming''s left-hand rule: the forefinger points in the direction of the magnetic field (into the page), the middle finger points in the direction of current (left to right). The thumb then points upward, indicating the force on the conductor is directed upward.", "correct_answer": "B", "concept_tags": ["flemings-left-hand-rule", "force-direction", "conductor-in-field"], "payload": {"question_id": "cuet-phy-mag-force-21", "subtopic": "force on current-carrying conductor (F=BIL sinОё)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Downward", "is_correct": false}, {"key": "B", "text": "Upward", "is_correct": true}, {"key": "C", "text": "Into the page", "is_correct": false}, {"key": "D", "text": "Out of the page", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Downward would result if the current direction were reversed (right to left). Re-apply Fleming''s left-hand rule with correct current direction.", "misconception": "Reversing the current direction in Fleming''s rule"}, {"option_key": "C", "hint": "The force cannot be along the magnetic field direction. F = IL Г— B is perpendicular to both I and B.", "misconception": "Confusing force direction with field direction"}, {"option_key": "D", "hint": "The magnetic field is into the page. The force must be perpendicular to both B and I, which means it must be in the plane of the page (up or down).", "misconception": "Confusing the force direction with the field''s opposite direction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a rectangular current loop ABCD placed in a uniform magnetic field B directed along the positive x-axis. The loop carries current I in the anticlockwise direction as seen from above. The plane of the loop is in the xz-plane. The net force on the loop is:", "explanation": "In a uniform magnetic field, the net force on any closed current loop is always zero. This is because the forces on opposite sides of the loop are equal in magnitude but opposite in direction. Sides AB and CD carry current parallel and antiparallel to B respectively, so the force on each is zero (sinОё = 0). Sides BC and DA are perpendicular to B and carry currents in opposite directions, so their forces cancel. The net force is zero, though a net torque may exist.", "correct_answer": "C", "concept_tags": ["current-loop", "uniform-field", "net-force-zero", "torque"], "payload": {"question_id": "cuet-phy-mag-force-22", "subtopic": "force on current-carrying conductor (F=BIL sinОё)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "BIL along the positive y-axis", "is_correct": false}, {"key": "B", "text": "2BIL along the positive z-axis", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "BIL along the negative x-axis", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Individual sides may experience forces, but in a uniform field, forces on opposite sides cancel exactly. The net force on a closed loop in a uniform field is always zero.", "misconception": "Summing magnitudes of forces without considering directions"}, {"option_key": "B", "hint": "Forces on sides BC and DA are equal and opposite, so they cancel. The net force is zero in a uniform field.", "misconception": "Forgetting that opposite sides carry current in opposite directions relative to B"}, {"option_key": "D", "hint": "No net translational force exists on a closed loop in a uniform field. A net force requires a non-uniform field.", "misconception": "Confusing net force with net torque on the loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows two long parallel wires P and Q separated by distance d, carrying currents Iв‚Ѓ and Iв‚‚ respectively in the same direction (upward). The force on wire Q due to wire P is:", "explanation": "Wire P produces a magnetic field at the location of Q. Using the right-hand rule, the field due to P at Q''s location points into the page (for P on the left carrying current upward). Wire Q carries current upward in this field (into the page), so by F = IL Г— B, the force on Q is directed toward P (attractive). The magnitude is F/L = Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd). Parallel currents in the same direction always attract.", "correct_answer": "A", "concept_tags": ["parallel-currents", "attractive-force", "right-hand-rule", "force-direction"], "payload": {"question_id": "cuet-phy-mag-force-23", "subtopic": "force between parallel currents", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Attractive, directed toward wire P, with magnitude Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd) per unit length", "is_correct": true}, {"key": "B", "text": "Repulsive, directed away from wire P, with magnitude Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd) per unit length", "is_correct": false}, {"key": "C", "text": "Attractive, directed toward wire P, with magnitude Ојв‚ЂIв‚ЃIв‚‚/(4ПЂd) per unit length", "is_correct": false}, {"key": "D", "text": "Zero, because the fields from the two wires cancel", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Same-direction currents attract, not repel. Opposite-direction currents repel. This is a fundamental result.", "misconception": "Reversing the attraction/repulsion rule for parallel currents"}, {"option_key": "C", "hint": "The formula uses 2ПЂ in the denominator, not 4ПЂ. F/L = Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd) is the standard result.", "misconception": "Confusing the 2ПЂ factor with 4ПЂ from Biot-Savart law"}, {"option_key": "D", "hint": "Each wire experiences a force due to the other wire''s field. The fields do not cancel at the wire locations.", "misconception": "Confusing field superposition at a midpoint with force on a wire"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram shows a charged particle of charge +q entering a region with both electric field E (upward) and magnetic field B (into the page) with velocity v directed to the right. For what value of v will the particle travel in a straight line, and what happens if the speed is doubled?", "explanation": "For straight-line motion, the electric force qE (upward) must balance the magnetic force qvB (downward, by Fleming''s left-hand rule for a positive charge moving right in a field into the page). So qE = qvB, giving v = E/B. If the speed is doubled to 2E/B, the magnetic force becomes 2qE (downward) while the electric force remains qE (upward). The net force is qE downward, and the particle curves downward.", "correct_answer": "D", "concept_tags": ["velocity-selector", "crossed-fields", "force-balance", "deflection"], "payload": {"question_id": "cuet-phy-mag-force-24", "subtopic": "velocity selector", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "v = E/B; if doubled, the particle curves upward", "is_correct": false}, {"key": "B", "text": "v = B/E; if doubled, the particle curves downward", "is_correct": false}, {"key": "C", "text": "v = E/B; if doubled, the particle continues in a straight line", "is_correct": false}, {"key": "D", "text": "v = E/B; if doubled, the particle curves downward", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "When v > E/B, the magnetic force (downward) exceeds the electric force (upward), so the net force is downward, not upward.", "misconception": "Reversing the direction of net force when magnetic force dominates"}, {"option_key": "B", "hint": "The balance condition is v = E/B, not B/E. From qE = qvB, solving for v gives E/B.", "misconception": "Inverting the velocity selector formula"}, {"option_key": "C", "hint": "Straight-line motion requires exact balance qE = qvB. Doubling v breaks this balance, so the particle must curve.", "misconception": "Thinking the particle remains undeflected at all speeds"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The work done by a magnetic force on a charged particle moving in a magnetic field is always zero.\n\nReason (R): The magnetic force on a moving charged particle is always perpendicular to its velocity.", "explanation": "Both A and R are true, and R is the correct explanation of A. The magnetic force F = qv Г— B is always perpendicular to the velocity v (since the cross product is perpendicular to both vectors). Work is defined as W = F В· ds, where ds is along the velocity. Since F is perpendicular to v (and hence to ds), the dot product F В· ds = 0 at every instant. Therefore the magnetic force does zero work. R directly explains why A is true.", "correct_answer": "A", "concept_tags": ["work-by-magnetic-force", "perpendicular-force", "lorentz-force"], "payload": {"question_id": "cuet-phy-mag-force-25", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: work = F В· ds = 0 precisely because F вЉҐ v. The perpendicularity is the reason for zero work.", "misconception": "Failing to connect perpendicularity of force with zero work done"}, {"option_key": "C", "hint": "R is correct. The cross product v Г— B is always perpendicular to v by the definition of the cross product.", "misconception": "Thinking the magnetic force can have a component along velocity"}, {"option_key": "D", "hint": "A is correct. Since F вЉҐ v always, W = в€«F В· ds = 0. The magnetic force cannot change the kinetic energy of a particle.", "misconception": "Thinking magnetic force can do work on a charged particle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The kinetic energy of a charged particle moving in a uniform magnetic field remains constant.\nReason (R): The magnetic force on a moving charge is always perpendicular to its velocity.", "explanation": "The assertion is correct: since the magnetic force does no work, the kinetic energy (and hence the speed) of the charged particle remains unchanged. The reason is also correct: F = qv Г— B is always perpendicular to v by the nature of the cross product. Furthermore, the reason correctly explains the assertion вЂ” it is precisely because the force is perpendicular to velocity that no work is done (W = F В· ds = 0 when F вЉҐ v), and therefore kinetic energy is conserved.", "correct_answer": "A", "concept_tags": ["kinetic-energy", "magnetic-force", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-26", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A. The perpendicularity of F to v means W = F В· v dt = 0, so KE is constant. The causal link is direct.", "misconception": "Failing to see the direct causal connection between perpendicular force and zero work"}, {"option_key": "C", "hint": "The reason is a fundamental property of the cross product (v Г— B is always perpendicular to v). R is definitely correct.", "misconception": "Doubting the perpendicularity of the magnetic force to velocity"}, {"option_key": "D", "hint": "The assertion is correct вЂ” speed and hence KE of a charged particle in a magnetic field do not change. This is experimentally verified.", "misconception": "Thinking magnetic field changes the kinetic energy of a charge"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A charged particle moving parallel to a magnetic field experiences no magnetic force and continues in a straight line.\n\nReason (R): The magnetic force on a charged particle is given by F = qE, where E is the electric field.", "explanation": "Assertion A is true: when a charged particle moves parallel (or antiparallel) to B, the angle Оё between v and B is 0В° (or 180В°), so F = qvB sinОё = 0. The particle experiences no deflection and moves in a straight line. Reason R is false: the magnetic force on a moving charge is F = qv Г— B (Lorentz force), not F = qE. The expression F = qE describes the electric force, not the magnetic force.", "correct_answer": "C", "concept_tags": ["parallel-motion", "zero-force", "lorentz-force", "electric-vs-magnetic"], "payload": {"question_id": "cuet-phy-mag-force-27", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": true}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R states an incorrect formula. The magnetic force is F = qv Г— B, not F = qE. F = qE is the electric force.", "misconception": "Confusing the electric force formula with the magnetic force formula"}, {"option_key": "B", "hint": "R is factually incorrect as it gives the electric force formula instead of the magnetic force formula.", "misconception": "Accepting an incorrect formula as true"}, {"option_key": "D", "hint": "A is correct: when v is parallel to B, sinОё = 0 in F = qvBsinОё, so F = 0 and the particle is undeflected.", "misconception": "Thinking a charged particle always experiences force in a magnetic field"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A current-carrying closed loop placed in a uniform magnetic field experiences a net force of zero.\nReason (R): The force on a current-carrying conductor in a magnetic field is given by F = I(L Г— B), where L is the length vector of the conductor.", "explanation": "The assertion is correct: for a closed loop in a uniform magnetic field, the net force is the vector sum of forces on all elements, which equals I(в€®dL) Г— B = I Г— 0 Г— B = 0, since the line integral of dL around a closed loop is zero. The reason is also correct: F = I(L Г— B) is indeed the expression for force on a straight current-carrying conductor. However, the reason by itself does not directly explain why the net force on a closed loop is zero вЂ” one also needs the fact that в€®dL = 0 for a closed loop in a uniform field. So R is not the complete explanation of A.", "correct_answer": "B", "concept_tags": ["closed-loop", "net-force-zero", "uniform-field", "force-on-conductor"], "payload": {"question_id": "cuet-phy-mag-force-28", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are correct, R only gives the force formula for a conductor. It does not explain why the sum of all such forces on a closed loop is zero. The explanation requires в€®dL = 0.", "misconception": "Assuming the force formula alone explains the zero net force on a closed loop"}, {"option_key": "C", "hint": "R is indeed correct. F = I(L Г— B) is the standard expression for force on a current-carrying conductor in a uniform field.", "misconception": "Doubting the validity of the force formula"}, {"option_key": "D", "hint": "A is correct. A closed current loop in a uniform magnetic field has zero net force (though it may experience a torque).", "misconception": "Confusing torque with net force on a loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Charged particle moving parallel to B\n(Q) Charged particle moving perpendicular to B\n(R) Charged particle moving at angle Оё (0В° < Оё < 90В°) to B\n(S) Charged particle at rest in B\n\nColumn II:\n(1) Helical path\n(2) Circular path\n(3) Straight line (no force)\n(4) No motion", "explanation": "P в†’ 3: When velocity is parallel to B, sinОё = 0, so F = 0 and the particle continues in a straight line. Q в†’ 2: When velocity is perpendicular to B, the constant perpendicular force causes circular motion. R в†’ 1: When velocity has both parallel and perpendicular components to B, the perpendicular component causes circular motion while the parallel component causes linear drift, resulting in a helical path. S в†’ 4: A stationary charge (v = 0) experiences no magnetic force and remains at rest.", "correct_answer": "D", "concept_tags": ["motion-in-magnetic-field", "circular-motion", "helical-motion", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-force-29", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Pв†’2, Qв†’3, Rв†’1, Sв†’4", "is_correct": false}, {"key": "B", "text": "Pв†’3, Qв†’1, Rв†’2, Sв†’4", "is_correct": false}, {"key": "C", "text": "Pв†’4, Qв†’2, Rв†’1, Sв†’3", "is_correct": false}, {"key": "D", "text": "Pв†’3, Qв†’2, Rв†’1, Sв†’4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Pв†’2 is wrong. A particle moving parallel to B experiences zero force and moves in a straight line, not a circle.", "misconception": "Confusing parallel and perpendicular motion in B"}, {"option_key": "B", "hint": "Qв†’1 is wrong. A particle moving perpendicular to B traces a circle, not a helix. A helix requires a velocity component along B.", "misconception": "Confusing circular and helical paths"}, {"option_key": "C", "hint": "Pв†’4 is wrong. A particle moving parallel to B is not stationary вЂ” it continues in a straight line since there is no magnetic force.", "misconception": "Thinking no force means no motion"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) SI unit of magnetic field\n(Q) Force between two parallel conductors carrying 1 A each, separated by 1 m, per unit length\n(R) Radius of circular path of charge q, mass m, speed v in field B\n(S) Condition for a charged particle to pass undeflected through crossed E and B fields\n\nColumn II:\n(1) mv/(qB)\n(2) 2 Г— 10вЃ»вЃ· N/m\n(3) v = E/B\n(4) Tesla (T)", "explanation": "P в†’ 4: The SI unit of magnetic field is Tesla (T). Q в†’ 2: Using F/L = Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd) with Iв‚Ѓ = Iв‚‚ = 1 A, d = 1 m: F/L = (4ПЂ Г— 10вЃ»вЃ· Г— 1 Г— 1)/(2ПЂ Г— 1) = 2 Г— 10вЃ»вЃ· N/m. This is the basis for the definition of the ampere. R в†’ 1: The radius of circular motion is r = mv/(qB), obtained by equating qvB = mvВІ/r. S в†’ 3: In a velocity selector, qE = qvB gives v = E/B.", "correct_answer": "C", "concept_tags": ["tesla", "ampere-definition", "radius-formula", "velocity-selector", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-force-30", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Pв†’4, Qв†’1, Rв†’2, Sв†’3", "is_correct": false}, {"key": "B", "text": "Pв†’4, Qв†’2, Rв†’3, Sв†’1", "is_correct": false}, {"key": "C", "text": "Pв†’4, Qв†’2, Rв†’1, Sв†’3", "is_correct": true}, {"key": "D", "text": "Pв†’2, Qв†’4, Rв†’1, Sв†’3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Qв†’1 is wrong. The force per unit length between two wires is a numerical value (2 Г— 10вЃ»вЃ· N/m), not the expression mv/(qB) which gives the radius of circular motion.", "misconception": "Mixing up the radius formula with the force between parallel conductors"}, {"option_key": "B", "hint": "Rв†’3 is wrong. The radius of circular path is r = mv/(qB), not v = E/B. The condition v = E/B applies to velocity selectors.", "misconception": "Confusing the radius formula with the velocity selector condition"}, {"option_key": "D", "hint": "Pв†’2 is wrong. The SI unit of magnetic field is Tesla (4), not 2 Г— 10вЃ»вЃ· N/m (which is the force per unit length between parallel conductors).", "misconception": "Confusing the unit of B with the force value used in defining the ampere"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "When a charged particle enters a uniform magnetic field at an angle Оё (where 0В° < Оё < 90В°) to the field direction, it follows a helical path with its axis along the magnetic field direction.", "explanation": "This statement is TRUE. When a charged particle enters a magnetic field at an angle Оё to B, its velocity has two components: vвЂ– = vcosОё (along B) and vвЉҐ = vsinОё (perpendicular to B). The perpendicular component causes circular motion, while the parallel component causes uniform linear motion along B. The combination of circular motion perpendicular to B and linear motion along B produces a helical (spiral) path with its axis along B.", "correct_answer": "A", "concept_tags": ["helical-motion", "velocity-components", "angle-entry"], "payload": {"question_id": "cuet-phy-mag-force-31", "subtopic": "helical motion", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The velocity component along B is unaffected by the magnetic force (F = qv Г— B has no component along B). This component causes forward drift while the perpendicular component causes circular motion, resulting in a helix.", "misconception": "Thinking the particle follows a circular path even when it has a velocity component along B"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The direction of force on a current-carrying conductor placed in a magnetic field can be determined using Fleming''s left-hand rule.", "explanation": "This statement is TRUE. Fleming''s left-hand rule states: if the forefinger points in the direction of the magnetic field (B), the middle finger points in the direction of current (I), then the thumb gives the direction of force (F) on the conductor. This rule is specifically used for determining the direction of force on a current-carrying conductor in a magnetic field (motor rule).", "correct_answer": "A", "concept_tags": ["flemings-left-hand-rule", "direction-of-force", "current-carrying-conductor"], "payload": {"question_id": "cuet-phy-mag-force-32", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Fleming''s left-hand rule is the standard rule for finding the direction of force on a current-carrying conductor in a magnetic field. It is widely used and correct.", "misconception": "Confusing Fleming''s left-hand rule (motor rule) with Fleming''s right-hand rule (generator/dynamo rule)"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The force between two parallel wires carrying currents in opposite directions is attractive.", "explanation": "This statement is FALSE. When two parallel wires carry currents in opposite directions, the force between them is repulsive, not attractive. Using the right-hand rule and F = IL Г— B, the magnetic field produced by one wire at the location of the other wire creates a force that pushes the wires apart. The rule is: same-direction currents attract, opposite-direction currents repel.", "correct_answer": "B", "concept_tags": ["parallel-currents", "repulsive-force", "opposite-currents"], "payload": {"question_id": "cuet-phy-mag-force-33", "subtopic": "force between parallel currents", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Apply the right-hand rule: the field from one wire at the other wire''s location, combined with the opposite current direction, gives a repulsive force. Same-direction currents attract; opposite-direction currents repel.", "misconception": "Confusing the rule for same and opposite direction currents"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A magnetic field can change the speed of a charged particle moving through it.", "explanation": "This statement is FALSE. The magnetic force on a charged particle is F = qv Г— B, which is always perpendicular to the velocity. A perpendicular force changes only the direction of velocity, not its magnitude (speed). Since no work is done by the magnetic force (W = F В· ds = 0 when F вЉҐ ds), the kinetic energy and hence the speed remain constant.", "correct_answer": "B", "concept_tags": ["magnetic-force", "speed-constant", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-34", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic force is always perpendicular to velocity and does zero work. Since work-energy theorem gives О”KE = W = 0, speed cannot change.", "misconception": "Assuming any force acting on a particle changes its speed"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A proton (mass = 1.67 Г— 10вЃ»ВІвЃ· kg, charge = 1.6 Г— 10вЃ»В№вЃ№ C) moves in a circular path of radius 0.1 m in a magnetic field of 0.5 T. The speed of the proton is approximately ________ m/s.", "explanation": "For circular motion in a magnetic field: qvB = mvВІ/r, giving v = qBr/m. Substituting: v = (1.6 Г— 10вЃ»В№вЃ№ Г— 0.5 Г— 0.1)/(1.67 Г— 10вЃ»ВІвЃ·) = (8 Г— 10вЃ»ВІВ№)/(1.67 Г— 10вЃ»ВІвЃ·) = 4.79 Г— 10вЃ¶ в‰€ 4.8 Г— 10вЃ¶ m/s.", "correct_answer": "D", "concept_tags": ["circular-motion", "proton-speed", "radius-formula"], "payload": {"question_id": "cuet-phy-mag-force-35", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "4.8 Г— 10вЃґ", "is_correct": false}, {"key": "B", "text": "4.8 Г— 10вЃµ", "is_correct": false}, {"key": "C", "text": "4.8 Г— 10вЃ·", "is_correct": false}, {"key": "D", "text": "4.8 Г— 10вЃ¶", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Check your powers of 10: (10вЃ»В№вЃ№ Г— 10вЃ»В№)/(10вЃ»ВІвЃ·) = 10вЃ»ВІвЃ°вЃєВІвЃ· = 10вЃ·, not 10вЃґ.", "misconception": "Error in handling powers of 10"}, {"option_key": "B", "hint": "The exponent should be 6, not 5. Recount: 10вЃ»В№вЃ№ Г— 10вЃ»В№ = 10вЃ»ВІвЃ°; dividing by 10вЃ»ВІвЃ· gives 10вЃ·; the coefficient 8/1.67 в‰€ 4.8 adjusts this to ~4.8 Г— 10вЃ¶.", "misconception": "Off-by-one error in exponent arithmetic"}, {"option_key": "C", "hint": "This would make the proton travel at nearly 1/6 the speed of light for a 0.5 T field and 0.1 m radius, which is too fast. Check the coefficient calculation.", "misconception": "Incorrect division of the numerical coefficient"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "One ampere is defined as that steady current which, when flowing through each of two infinitely long, straight, parallel conductors placed 1 m apart in vacuum, produces a force per unit length of _____ N/m between them.", "explanation": "The SI definition of one ampere is based on the force between two parallel current-carrying conductors. Using F/L = Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd), with Iв‚Ѓ = Iв‚‚ = 1 A and d = 1 m: F/L = (4ПЂ Г— 10вЃ»вЃ· Г— 1 Г— 1)/(2ПЂ Г— 1) = 2 Г— 10вЃ»вЃ· N/m. This value defines the ampere in the SI system.", "correct_answer": "D", "concept_tags": ["ampere-definition", "parallel-conductors", "force-per-unit-length", "SI-units"], "payload": {"question_id": "cuet-phy-mag-force-36", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "4ПЂ Г— 10вЃ»вЃ·", "is_correct": false}, {"key": "B", "text": "1 Г— 10вЃ»вЃ·", "is_correct": false}, {"key": "C", "text": "4 Г— 10вЃ»вЃ·", "is_correct": false}, {"key": "D", "text": "2 Г— 10вЃ»вЃ·", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4ПЂ Г— 10вЃ»вЃ· is the value of Ојв‚Ђ (permeability of free space), not the force per unit length. F/L = Ојв‚ЂIв‚ЃIв‚‚/(2ПЂd) = Ојв‚Ђ/(2ПЂ) = 2 Г— 10вЃ»вЃ· N/m.", "misconception": "Confusing Ојв‚Ђ with the force per unit length"}, {"option_key": "B", "hint": "1 Г— 10вЃ»вЃ· is half the correct value. The calculation gives Ојв‚Ђ/(2ПЂ) = 4ПЂ Г— 10вЃ»вЃ·/(2ПЂ) = 2 Г— 10вЃ»вЃ·, not 1 Г— 10вЃ»вЃ·.", "misconception": "Arithmetic error in simplifying Ојв‚Ђ/(2ПЂ)"}, {"option_key": "C", "hint": "4 Г— 10вЃ»вЃ· is twice the correct value. Carefully simplify: 4ПЂ Г— 10вЃ»вЃ·/(2ПЂ) = 2 Г— 10вЃ»вЃ·.", "misconception": "Cancellation error when dividing 4ПЂ by 2ПЂ"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a mass spectrometer, singly ionized ions of two isotopes of an element (masses mв‚Ѓ = 20 u and mв‚‚ = 22 u, where 1 u = 1.66 Г— 10вЃ»ВІвЃ· kg) are accelerated through a potential difference of 10 kV and then enter a uniform magnetic field of 0.2 T perpendicular to their velocity. The ions travel in semicircular paths and strike a photographic plate. What is the separation between the two lines formed on the photographic plate?", "explanation": "After acceleration, KE = qV, so v = в€љ(2qV/m). The radius of the semicircular path is r = mv/(qB) = (m/(qB))в€љ(2qV/m) = в€љ(2mV/q)/B. The separation on the plate equals the difference in diameters: О”x = 2rв‚‚ в€’ 2rв‚Ѓ = (2/B)в€љ(2V/q)(в€љmв‚‚ в€’ в€љmв‚Ѓ). With q = 1.6 Г— 10вЃ»В№вЃ№ C, V = 10вЃґ V, B = 0.2 T: в€љ(2V/q) = в€љ(2 Г— 10вЃґ/(1.6 Г— 10вЃ»В№вЃ№)) = в€љ(1.25 Г— 10ВІВі) = 1.118 Г— 10В№В№В·вЃµ. Computing: r = в€љ(2mV/q)/B. For mв‚Ѓ = 20 Г— 1.66 Г— 10вЃ»ВІвЃ· = 3.32 Г— 10вЃ»ВІвЃ¶ kg: rв‚Ѓ = в€љ(2 Г— 3.32 Г— 10вЃ»ВІвЃ¶ Г— 10вЃґ/1.6 Г— 10вЃ»В№вЃ№)/0.2 = в€љ(4.15 Г— 10вЃ»Ві)/0.2 = 0.0644/0.2 = 0.322 m. For mв‚‚ = 22 Г— 1.66 Г— 10вЃ»ВІвЃ· = 3.652 Г— 10вЃ»ВІвЃ¶ kg: rв‚‚ = в€љ(2 Г— 3.652 Г— 10вЃ»ВІвЃ¶ Г— 10вЃґ/1.6 Г— 10вЃ»В№вЃ№)/0.2 = в€љ(4.565 Г— 10вЃ»Ві)/0.2 = 0.0676/0.2 = 0.338 m. Separation = 2(rв‚‚ в€’ rв‚Ѓ) = 2(0.338 в€’ 0.322) = 2 Г— 0.016 = 0.032 m в‰€ 3.2 cm.", "correct_answer": "B", "concept_tags": ["mass-spectrometer", "isotopes", "semicircular-path", "separation", "scenario-based"], "payload": {"question_id": "cuet-phy-mag-force-37", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6 cm", "is_correct": false}, {"key": "B", "text": "3.2 cm", "is_correct": true}, {"key": "C", "text": "6.4 cm", "is_correct": false}, {"key": "D", "text": "0.8 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.6 cm is the difference in radii (rв‚‚ в€’ rв‚Ѓ), not diameters. The separation on the photographic plate equals the difference in diameters: 2(rв‚‚ в€’ rв‚Ѓ).", "misconception": "Forgetting to multiply the radius difference by 2 for the diameter difference"}, {"option_key": "C", "hint": "6.4 cm is double the correct answer. Check that you are not multiplying by 4 instead of 2 when converting from radius to diameter difference.", "misconception": "Doubling the diameter difference instead of the radius difference"}, {"option_key": "D", "hint": "0.8 cm is too small. This may result from an error in the calculation of radii or forgetting to use the correct mass values.", "misconception": "Arithmetic error in computing the radii"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "What is the maximum kinetic energy (in MeV) that the protons can achieve in this cyclotron? (1 MeV = 1.6 Г— 10вЃ»В№Ві J)", "explanation": "The maximum speed is achieved when the proton reaches the edge of the dee: v_max = qBR/m = (1.6 Г— 10вЃ»В№вЃ№ Г— 1.5 Г— 0.5)/(1.67 Г— 10вЃ»ВІвЃ·) = (1.2 Г— 10вЃ»В№вЃ№)/(1.67 Г— 10вЃ»ВІвЃ·) = 7.19 Г— 10вЃ· m/s. Maximum KE = ВЅmvВІ = ВЅ Г— 1.67 Г— 10вЃ»ВІвЃ· Г— (7.19 Г— 10вЃ·)ВІ = ВЅ Г— 1.67 Г— 10вЃ»ВІвЃ· Г— 5.17 Г— 10В№вЃµ = 4.32 Г— 10вЃ»В№ВІ J. Converting to MeV: 4.32 Г— 10вЃ»В№ВІ / 1.6 Г— 10вЃ»В№Ві = 27 MeV. Alternatively, KE = qВІBВІRВІ/(2m) = (1.6 Г— 10вЃ»В№вЃ№)ВІ Г— (1.5)ВІ Г— (0.5)ВІ / (2 Г— 1.67 Г— 10вЃ»ВІвЃ·) = (2.56 Г— 10вЃ»ВівЃё Г— 2.25 Г— 0.25)/(3.34 Г— 10вЃ»ВІвЃ·) = 1.44 Г— 10вЃ»ВівЃё/(3.34 Г— 10вЃ»ВІвЃ·) в‰€ 4.31 Г— 10вЃ»В№ВІ J в‰€ 27 MeV.", "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton-acceleration", "dee-radius"], "payload": {"question_id": "cuet-phy-mag-force-38", "subtopic": "cyclotron", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "13.5 MeV", "is_correct": false}, {"key": "B", "text": "54 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "6.75 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is half the correct answer. Ensure you are using KE = qВІBВІRВІ/(2m) and not missing any squared term.", "misconception": "Missing the square on one of the quantities in the KE formula"}, {"option_key": "B", "hint": "This is double the correct answer. Check the factor of 2 in the denominator of KE = ВЅmvВІ.", "misconception": "Forgetting the factor of ВЅ in the kinetic energy formula"}, {"option_key": "D", "hint": "This is one-fourth of the correct value. Verify that you have squared both B and R in the formula.", "misconception": "Forgetting to square the magnetic field or radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following steps in the correct order for determining the force on a current-carrying conductor placed in a magnetic field using the formula F = BIL sinОё.", "explanation": "The correct sequence is: (Step 2) First identify the given quantities: B, I, and L. (Step 4) Determine the angle Оё between the current direction and the magnetic field. (Step 1) Substitute all values into F = BIL sinОё to calculate the magnitude. (Step 3) Finally, use Fleming''s left-hand rule to find the direction of the force.", "correct_answer": "B", "concept_tags": ["force-calculation-steps", "BIL-formula", "flemings-rule"], "payload": {"question_id": "cuet-phy-mag-force-39", "subtopic": "force on current-carrying conductor (F=BIL sinОё)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "2 в†’ 1 в†’ 4 в†’ 3", "is_correct": false}, {"key": "B", "text": "2 в†’ 4 в†’ 1 в†’ 3", "is_correct": true}, {"key": "C", "text": "4 в†’ 2 в†’ 3 в†’ 1", "is_correct": false}, {"key": "D", "text": "3 в†’ 2 в†’ 4 в†’ 1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You cannot calculate F = BIL sinОё (step 1) before determining Оё (step 4). The angle is needed for the substitution.", "misconception": "Attempting calculation before all variables are identified"}, {"option_key": "C", "hint": "You should identify B, I, and L (step 2) before determining the angle (step 4), as you need to know the setup first.", "misconception": "Starting with angle determination before understanding the physical setup"}, {"option_key": "D", "hint": "Fleming''s rule (step 3) gives direction, which is typically determined after computing the magnitude. You also need B and I first.", "misconception": "Determining force direction before identifying the physical quantities"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following phenomena in order of increasing magnetic force experienced, from least to greatest, for identical charged particles (charge q, mass m) moving with speed v.", "explanation": "The magnetic force on a charged particle is F = qvB sinОё. As the angle Оё between v and B increases from 0В° to 90В°, sinОё increases from 0 to 1. At Оё = 0В° (parallel): F = 0. At Оё = 30В°: F = 0.5qvB. At Оё = 60В°: F = 0.866qvB. At Оё = 90В° (perpendicular): F = qvB (maximum). The order from least to greatest force is: parallel (0В°) в†’ 30В° в†’ 60В° в†’ perpendicular (90В°), i.e., 1 в†’ 2 в†’ 3 в†’ 4.", "correct_answer": "D", "concept_tags": ["angle-dependence", "sinОё-variation", "magnetic-force-comparison"], "payload": {"question_id": "cuet-phy-mag-force-40", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "4 в†’ 3 в†’ 2 в†’ 1", "is_correct": false}, {"key": "B", "text": "1 в†’ 3 в†’ 2 в†’ 4", "is_correct": false}, {"key": "C", "text": "2 в†’ 1 в†’ 3 в†’ 4", "is_correct": false}, {"key": "D", "text": "1 в†’ 2 в†’ 3 в†’ 4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This is the order from greatest to least, but the question asks for least to greatest (increasing order).", "misconception": "Reversing the required ordering direction"}, {"option_key": "B", "hint": "sin60В° > sin30В°, so the force at 60В° is greater than at 30В°. Items 2 and 3 are in wrong order here.", "misconception": "Incorrectly ranking sin30В° and sin60В°"}, {"option_key": "C", "hint": "A particle moving parallel to B (item 1) has zero force, which is less than force at 30В° (item 2). Item 1 should come first.", "misconception": "Thinking a parallel-moving particle experiences some force"}]}}]'::jsonb, 'deploy-2026-03-05-b02');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The deflection in a moving coil galvanometer is proportional to the current passing through it because the restoring torque is proportional to:", "explanation": "In a moving coil galvanometer, the restoring torque is provided by the phosphor-bronze spring and is proportional to the angle of deflection (П„ = kОё). At equilibrium, the deflecting torque (NIAB) equals the restoring torque (kОё), giving Оё = (NAB/k)I. Hence deflection is proportional to current because the restoring torque is proportional to the twist/deflection angle.", "correct_answer": "D", "concept_tags": ["moving coil galvanometer", "restoring torque", "deflection"], "payload": {"question_id": "cuet-phy-mag-devices-01", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "The magnetic field intensity", "is_correct": false}, {"key": "B", "value": "The number of turns of the coil", "is_correct": false}, {"key": "C", "value": "The area of the coil", "is_correct": false}, {"key": "D", "value": "The angle of twist of the suspension", "is_correct": true}], "elimination_hints": ["Magnetic field, number of turns, and area are constants of the galvanometerвЂ”they don''t change with deflection.", "The restoring torque must vary with deflection for equilibrium to be achieved at different currents.", "Think about what physically changes as the coil rotatesвЂ”only the twist angle changes."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The time period of a charged particle revolving in a cyclotron is independent of:", "explanation": "In a cyclotron, the time period T = 2ПЂm/(qB). This expression shows that T depends only on mass (m), charge (q), and magnetic field (B). It does not depend on the speed or energy of the particle (non-relativistic case). This is the key principle that makes the cyclotron work -- particles take the same time per revolution regardless of their speed, allowing a fixed-frequency oscillating electric field to accelerate them.", "correct_answer": "C", "concept_tags": ["cyclotron-frequency", "time-period", "independence-of-speed"], "payload": {"question_id": "cuet-phy-mag-devices-02", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Mass of the particle", "is_correct": false}, {"key": "B", "text": "Magnetic field strength", "is_correct": false}, {"key": "C", "text": "Speed of the particle", "is_correct": true}, {"key": "D", "text": "Charge of the particle", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The formula T = 2ПЂm/(qB) explicitly contains mass m in the numerator, so the time period directly depends on mass.", "misconception": "Overlooking the mass dependence in the cyclotron frequency formula"}, {"option_key": "B", "hint": "Magnetic field B appears in the denominator of T = 2ПЂm/(qB). Increasing B decreases the time period, so T depends on B.", "misconception": "Ignoring the role of magnetic field in determining the cyclotron period"}, {"option_key": "D", "hint": "Charge q is in the denominator of T = 2ПЂm/(qB). A particle with larger charge has a shorter time period, so T does depend on charge.", "misconception": "Forgetting that charge influences the cyclotron frequency"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The material used for the suspension wire in a moving coil galvanometer is phosphor-bronze because it has:", "explanation": "Phosphor-bronze is used for the suspension wire/spring in a moving coil galvanometer because it has a very small restoring torque per unit twist (low torsional constant). This ensures high sensitivityвЂ”even a small current produces a noticeable deflection. While it is also non-magnetic and has low temperature coefficient, the primary reason is the small restoring torque.", "correct_answer": "B", "concept_tags": ["galvanometer construction", "phosphor-bronze", "sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-03", "subtopic": "Galvanometer construction", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "High electrical conductivity", "is_correct": false}, {"key": "B", "value": "Small restoring torque per unit twist", "is_correct": true}, {"key": "C", "value": "High magnetic permeability", "is_correct": false}, {"key": "D", "value": "Large Young''s modulus", "is_correct": false}], "elimination_hints": ["Copper has higher conductivity but is not usedвЂ”so conductivity is not the key property.", "High magnetic permeability would interfere with the magnetic field, making it undesirable.", "Large Young''s modulus means stiffness, which would reduce sensitivity, not improve it."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a moving coil galvanometer, the coil is wound on an aluminium frame to:", "explanation": "The coil in a moving coil galvanometer is wound on an aluminium frame to provide electromagnetic damping. When the coil rotates in the magnetic field, eddy currents are induced in the aluminium frame (which is a conductor). These eddy currents oppose the motion of the coil (by Lenz''s law), bringing the coil to rest quickly without oscillations. This is known as dead-beat behavior.", "correct_answer": "B", "concept_tags": ["electromagnetic damping", "eddy currents", "aluminium frame"], "payload": {"question_id": "cuet-phy-mag-devices-04", "subtopic": "Galvanometer construction", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "Increase the magnetic flux through the coil", "is_correct": false}, {"key": "B", "value": "Provide electromagnetic damping", "is_correct": true}, {"key": "C", "value": "Increase the moment of inertia of the coil", "is_correct": false}, {"key": "D", "value": "Make the coil lighter", "is_correct": false}], "elimination_hints": ["The frame is made of aluminium (a conductor)вЂ”think about what happens when a conductor moves in a magnetic field.", "Increasing moment of inertia would slow the response, which is not desirable.", "If making the coil lighter were the goal, a non-metallic frame would be even lighter."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A cyclotron is used to accelerate:", "explanation": "A cyclotron is used to accelerate charged particles such as protons, deuterons, and alpha particles. It cannot accelerate neutral particles (no Lorentz force) or electrons (their small mass causes relativistic effects at modest energies, making the cyclotron frequency condition invalid). The device uses a combination of electric and magnetic fields to accelerate charged particles to high energies.", "correct_answer": "B", "concept_tags": ["cyclotron", "charged-particles", "particle-accelerator"], "payload": {"question_id": "cuet-phy-mag-devices-05", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Electrons", "is_correct": false}, {"key": "B", "text": "Protons and deuterons", "is_correct": true}, {"key": "C", "text": "Neutral atoms", "is_correct": false}, {"key": "D", "text": "Neutrons", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small mass (9.1 x 10^-31 kg), so they quickly reach relativistic speeds where their mass increases significantly, violating the constant cyclotron frequency condition.", "misconception": "Thinking cyclotron works for all charged particles regardless of mass"}, {"option_key": "C", "hint": "Neutral atoms have no net charge, so they experience no Lorentz force (F = qv x B = 0) and cannot be accelerated by electric or magnetic fields.", "misconception": "Forgetting that cyclotron requires charged particles"}, {"option_key": "D", "hint": "Neutrons are uncharged particles. The cyclotron relies on the magnetic force (qvB) to bend particle paths, which is zero for neutral particles.", "misconception": "Confusing neutrons with charged particles"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, one should connect:", "explanation": "A galvanometer is converted into a voltmeter by connecting a high resistance in series with it. This limits the current through the galvanometer to its full-scale deflection current (Ig) when the desired maximum voltage V is applied. The required series resistance R = V/Ig - G, where G is the galvanometer resistance. The high series resistance ensures that the voltmeter draws negligible current from the circuit.", "correct_answer": "A", "concept_tags": ["galvanometer-conversion", "voltmeter", "series-resistance"], "payload": {"question_id": "cuet-phy-mag-devices-06", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "A high resistance in series", "is_correct": true}, {"key": "B", "text": "A low resistance in series", "is_correct": false}, {"key": "C", "text": "A high resistance in parallel", "is_correct": false}, {"key": "D", "text": "A low resistance in parallel", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A low resistance in series would barely increase the total resistance, so the galvanometer would still draw too much current and could be damaged. The resistance must be high to limit current to Ig.", "misconception": "Not understanding that a voltmeter must have very high resistance"}, {"option_key": "C", "hint": "A high resistance in parallel would have little effect since most current would still flow through the lower-resistance galvanometer. Parallel connection is used for ammeter conversion.", "misconception": "Confusing series and parallel configurations for meter conversion"}, {"option_key": "D", "hint": "A low resistance in parallel (shunt) is used to convert a galvanometer into an ammeter, not a voltmeter.", "misconception": "Confusing ammeter and voltmeter conversion methods"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When a shunt of resistance S is connected across a galvanometer of resistance G, the fraction of total current that passes through the galvanometer is:", "explanation": "When a shunt S is connected in parallel with galvanometer G, the current divides in the inverse ratio of resistances. The current through galvanometer Ig = I Г— S/(G + S). Therefore, the fraction Ig/I = S/(G + S). This shows that a smaller shunt diverts more current away from the galvanometer.", "correct_answer": "D", "concept_tags": ["shunt resistance", "current division", "parallel circuit"], "payload": {"question_id": "cuet-phy-mag-devices-07", "subtopic": "shunt resistance", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "G/(G + S)", "is_correct": false}, {"key": "B", "value": "G/S", "is_correct": false}, {"key": "C", "value": "S/G", "is_correct": false}, {"key": "D", "value": "S/(G + S)", "is_correct": true}], "elimination_hints": ["In a parallel combination, current through a branch is inversely proportional to its resistance.", "The galvanometer has resistance G, so less current flows through it when G is largeвЂ”the fraction should decrease with increasing G.", "Check: if S = G, the fraction should be 1/2 (equal split). Only S/(G + S) gives G/(G+G) = 1/2."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a moving coil galvanometer, the restoring torque is provided by:", "explanation": "In a moving coil galvanometer, the coil experiences a deflecting torque (П„ = NIAB) due to the magnetic field. The restoring torque is provided by a pair of phosphor-bronze springs (hair springs) attached to the coil. At equilibrium, the restoring torque (kОё) equals the deflecting torque (NIAB), giving Оё = NIAB/k. The springs also serve as leads to carry current to and from the coil.", "correct_answer": "D", "concept_tags": ["moving-coil-galvanometer", "restoring-torque", "spring", "equilibrium"], "payload": {"question_id": "cuet-phy-mag-devices-08", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic field", "is_correct": false}, {"key": "B", "text": "Gravity", "is_correct": false}, {"key": "C", "text": "The soft iron core", "is_correct": false}, {"key": "D", "text": "The phosphor-bronze spring", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic field produces the deflecting torque (П„ = NIAB), not the restoring torque. The restoring mechanism must oppose the deflection.", "misconception": "Confusing deflecting torque with restoring torque"}, {"option_key": "B", "hint": "Gravity is not used as the restoring mechanism in a moving coil galvanometer. The instrument can work in any orientation because springs provide the restoring torque.", "misconception": "Confusing with gravity-based instruments"}, {"option_key": "C", "hint": "The soft iron core makes the magnetic field radial (uniform in all positions of the coil) to ensure linear deflection, but it does not provide the restoring torque.", "misconception": "Confusing the role of the iron core with the spring"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer of resistance 100 О© gives full-scale deflection for a current of 10 mA. The resistance to be connected in series to convert it into a voltmeter of range 0-100 V is:", "explanation": "To convert a galvanometer to a voltmeter, a high resistance R is connected in series. Using R = V/Ig - G, where V = 100 V, Ig = 10 mA = 0.01 A, and G = 100 О©: R = 100/0.01 - 100 = 10000 - 100 = 9900 О©. The total resistance of the voltmeter becomes G + R = 10000 О©, ensuring that only Ig flows when V is applied across it.", "correct_answer": "D", "concept_tags": ["galvanometer-to-voltmeter", "series-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-devices-09", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "10000 О©", "is_correct": false}, {"key": "B", "text": "1000 О©", "is_correct": false}, {"key": "C", "text": "10 О©", "is_correct": false}, {"key": "D", "text": "9900 О©", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10000 О© is V/Ig = 100/0.01, which is the total resistance needed. But the question asks for the series resistance R alone, so you must subtract G: R = 10000 - 100 = 9900 О©.", "misconception": "Forgetting to subtract the galvanometer resistance G from V/Ig"}, {"option_key": "B", "hint": "1000 О© would give a total resistance of 1100 О©, limiting the voltmeter range to only V = Ig x (G + R) = 0.01 x 1100 = 11 V, not 100 V.", "misconception": "Arithmetic error or using wrong formula"}, {"option_key": "C", "hint": "10 О© is far too small. With R = 10 О©, total resistance = 110 О©, giving range V = 0.01 x 110 = 1.1 V only.", "misconception": "Confusing voltmeter conversion with ammeter conversion (where low resistance is used)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 О© and gives full-scale deflection for a current of 5 mA. To convert it into an ammeter reading up to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer into an ammeter, a low resistance (shunt) S is connected in parallel. Using the formula S = Ig Г— G / (I в€’ Ig), where Ig = 5 mA = 0.005 A, G = 50 О©, and I = 5 A: S = (0.005 Г— 50) / (5 в€’ 0.005) = 0.25 / 4.995 в‰€ 0.05 О©. Since 4.995 в‰€ 5, we get S в‰€ 0.05 О©.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "shunt resistance", "galvanometer"], "payload": {"question_id": "cuet-phy-mag-devices-10", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "0.5 О©", "is_correct": false}, {"key": "B", "value": "0.005 О©", "is_correct": false}, {"key": "C", "value": "0.05 О©", "is_correct": true}, {"key": "D", "value": "5 О©", "is_correct": false}], "elimination_hints": ["The shunt must be very small compared to the galvanometer resistance of 50 О©.", "5 О© is too largeвЂ”it would not divert enough current away from the galvanometer.", "Use S = IgG/(Iв€’Ig) and approximate Iв€’Ig в‰€ I when I >> Ig."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a galvanometer can be increased by:", "explanation": "Current sensitivity is defined as Оё/I = NAB/k. To increase it, we can increase N (number of turns), A (area of coil), B (magnetic field strength), or decrease k (torsional constant of the spring). Using a stronger magnetic field directly increases current sensitivity.", "correct_answer": "C", "concept_tags": ["current sensitivity", "galvanometer sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-11", "subtopic": "current sensitivity", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "Increasing the torsional constant of the spring", "is_correct": false}, {"key": "B", "value": "Decreasing the number of turns in the coil", "is_correct": false}, {"key": "C", "value": "Using a stronger magnetic field", "is_correct": true}, {"key": "D", "value": "Reducing the area of the coil", "is_correct": false}], "elimination_hints": ["Current sensitivity = NAB/k. Increasing k (denominator) would decrease sensitivity.", "Decreasing N or A would reduce the numerator, thus reducing sensitivity.", "Only an option that increases NAB or decreases k will increase sensitivity."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a moving coil galvanometer can be increased by:", "explanation": "Current sensitivity Is = NAB/k, where N is the number of turns, A is the area of the coil, B is the magnetic field strength, and k is the torsional spring constant. To increase current sensitivity, we can increase N, A, or B, or decrease k (use a weaker spring). Increasing the spring constant k would decrease the sensitivity, not increase it.", "correct_answer": "C", "concept_tags": ["current-sensitivity", "galvanometer", "NAB-by-k"], "payload": {"question_id": "cuet-phy-mag-devices-12", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "Increasing the spring constant k", "is_correct": false}, {"key": "B", "text": "Decreasing the number of turns N", "is_correct": false}, {"key": "C", "text": "Increasing the magnetic field strength B", "is_correct": true}, {"key": "D", "text": "Decreasing the area of the coil A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since Is = NAB/k, increasing k (denominator) would decrease the sensitivity, making the galvanometer less sensitive to small currents.", "misconception": "Confusing direct and inverse proportionality in the sensitivity formula"}, {"option_key": "B", "hint": "N appears in the numerator of Is = NAB/k. Decreasing N would reduce sensitivity, not increase it.", "misconception": "Incorrectly identifying N as being in the denominator"}, {"option_key": "D", "hint": "Area A is in the numerator of Is = NAB/k. A larger coil area increases the torque for a given current, increasing sensitivity.", "misconception": "Thinking smaller area gives better sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The voltage sensitivity of a galvanometer of resistance G, having N turns of area A in magnetic field B with spring constant k is given by:", "explanation": "Voltage sensitivity Vs = deflection per unit voltage = Оё/V. Since Оё/I (current sensitivity) = NAB/k, and V = IR (where R is the total resistance = G for the galvanometer alone), we get Vs = Оё/V = (Оё/I) x (1/G) = NAB/(kG). Thus voltage sensitivity depends inversely on the galvanometer resistance, unlike current sensitivity.", "correct_answer": "C", "concept_tags": ["voltage-sensitivity", "galvanometer", "NAB-by-kG"], "payload": {"question_id": "cuet-phy-mag-devices-13", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "NAB/k", "is_correct": false}, {"key": "B", "text": "NABk/G", "is_correct": false}, {"key": "C", "text": "NAB/(kG)", "is_correct": true}, {"key": "D", "text": "NAG/(kB)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "NAB/k is the current sensitivity (Оё/I), not the voltage sensitivity. Voltage sensitivity = current sensitivity / G = NAB/(kG).", "misconception": "Confusing current sensitivity with voltage sensitivity"}, {"option_key": "B", "hint": "This expression has k in the numerator. Since higher spring constant k means lower deflection per unit current, k must be in the denominator.", "misconception": "Placing k incorrectly in the formula"}, {"option_key": "D", "hint": "This expression has G in the numerator and B in the denominator, both of which are inverted. Higher B gives more torque (hence more sensitivity), and higher G gives less voltage sensitivity.", "misconception": "Swapping the positions of B and G"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A cyclotron''s oscillator frequency is 10 MHz. If the magnetic field is 0.5 T, the charge-to-mass ratio (q/m) of the particle being accelerated is approximately:", "explanation": "The cyclotron frequency is given by f = qB/(2ПЂm), so q/m = 2ПЂf/B. Substituting the values: q/m = 2ПЂ x 10 x 10^6 / 0.5 = 2 x 3.14 x 10^7 / 0.5 = 6.28 x 10^7 / 0.5 = 1.256 x 10^8 C/kg в‰€ 1.26 x 10^8 C/kg. This is close to the q/m ratio of a proton (e/mp = 1.6 x 10^-19 / 1.67 x 10^-27 в‰€ 0.96 x 10^8 C/kg), suggesting a slightly different ion.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "charge-to-mass-ratio", "numerical"], "payload": {"question_id": "cuet-phy-mag-devices-14", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 x 10^7 C/kg", "is_correct": false}, {"key": "B", "text": "1.26 x 10^8 C/kg", "is_correct": true}, {"key": "C", "text": "3.14 x 10^8 C/kg", "is_correct": false}, {"key": "D", "text": "2.0 x 10^7 C/kg", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value (6.28 x 10^7) equals 2ПЂf but forgets to divide by B. The correct formula is q/m = 2ПЂf/B, and you must divide by 0.5 T.", "misconception": "Forgetting to divide by the magnetic field B"}, {"option_key": "C", "hint": "This value (3.14 x 10^8) corresponds to dividing by B but using ПЂf instead of 2ПЂf, or an arithmetic error in the multiplication.", "misconception": "Incorrect substitution in the cyclotron frequency formula"}, {"option_key": "D", "hint": "This value is significantly off from the correct calculation. With f = 10^7 Hz and B = 0.5 T, q/m = 2ПЂ x 10^7 / 0.5 = 4ПЂ x 10^7 в‰€ 1.26 x 10^8.", "misconception": "Major arithmetic error or using the wrong formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 О© and gives full-scale deflection for a current of 1 mA. To convert it into an ammeter of range 0 to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer to an ammeter, a shunt resistance S is connected in parallel. Using the formula S = Ig x G/(I - Ig), where Ig = 1 mA = 0.001 A, G = 50 О©, and I = 5 A: S = 0.001 x 50 / (5 - 0.001) = 0.05 / 4.999 в‰€ 0.01 О©. Since Ig << I, we can approximate S в‰€ Ig x G / I = 0.001 x 50 / 5 = 0.01 О©.", "correct_answer": "A", "concept_tags": ["galvanometer-to-ammeter", "shunt-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-devices-15", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 О©", "is_correct": true}, {"key": "B", "text": "0.05 О©", "is_correct": false}, {"key": "C", "text": "1.0 О©", "is_correct": false}, {"key": "D", "text": "50 О©", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "0.05 О© = Ig x G = 0.001 x 50. This is the numerator of the formula but you must divide by (I - Ig) в‰€ 5 to get the shunt value.", "misconception": "Using S = Ig x G instead of the complete formula S = Ig x G/(I - Ig)"}, {"option_key": "C", "hint": "1.0 О© is too high for a shunt. The shunt must be much smaller than the galvanometer resistance to divert most current away from the coil.", "misconception": "Not understanding that shunt resistance should be very small"}, {"option_key": "D", "hint": "Using S = G = 50 О© means equal resistance in parallel, which would only double the range, not increase it 5000 times.", "misconception": "Thinking the shunt should equal the galvanometer resistance"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum kinetic energy of a charged particle emerging from a cyclotron of radius R, magnetic field B, charge q, and mass m is:", "explanation": "In a cyclotron, the charged particle moves in a circular path where the magnetic force provides centripetal force: qvB = mv^2/R, giving v = qBR/m. The maximum kinetic energy is KE = (1/2)mv^2 = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m). Here R is the radius of the largest semicircular path (the dee radius).", "correct_answer": "A", "concept_tags": ["cyclotron", "kinetic-energy", "maximum-energy", "dee-radius"], "payload": {"question_id": "cuet-phy-mag-devices-16", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "qВІBВІRВІ/(2m)", "is_correct": true}, {"key": "B", "text": "qBR/(2m)", "is_correct": false}, {"key": "C", "text": "qВІBВІRВІ/(m)", "is_correct": false}, {"key": "D", "text": "qBВІRВІ/(2m)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This expression has dimensions of velocity (m/s), not energy (kg m^2/s^2). The kinetic energy must involve squared terms of q, B, and R.", "misconception": "Confusing the expression for velocity with kinetic energy"}, {"option_key": "C", "hint": "This is twice the correct answer. KE = (1/2)mv^2 has the factor of 1/2, so the result should be q^2B^2R^2/(2m), not q^2B^2R^2/m.", "misconception": "Forgetting the factor of 1/2 in the kinetic energy formula"}, {"option_key": "D", "hint": "This expression is missing one factor of q. Since v = qBR/m, the KE = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m), requiring q squared.", "misconception": "Error in squaring the velocity expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 40 О© gives full-scale deflection for a current of 2 mA. It is converted into a voltmeter of range 0вЂ“20 V and also into an ammeter of range 0вЂ“5 A. The ratio of the resistance of the voltmeter to the resistance of the ammeter is:", "explanation": "For the voltmeter: Total resistance Rv = V/Ig = 20/0.002 = 10,000 О©. For the ammeter: The shunt S = IgG/(I в€’ Ig) = (0.002 Г— 40)/(5 в€’ 0.002) = 0.08/4.998 в‰€ 0.016 О©. Total ammeter resistance Ra = GS/(G + S) в‰€ S = 0.016 О© (since S << G). Ratio Rv/Ra = 10,000/0.016 = 625,000. Alternatively, Rv/Ra = (V/Ig) / [IgG/(Iв€’Ig)] = V(Iв€’Ig)/(IgВІG) в‰€ VI/(IgВІG) = (20 Г— 5)/(0.000004 Г— 40) = 100/0.00016 = 625,000.", "correct_answer": "D", "concept_tags": ["voltmeter resistance", "ammeter resistance", "conversion"], "payload": {"question_id": "cuet-phy-mag-devices-17", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "250", "is_correct": false}, {"key": "B", "value": "2,500", "is_correct": false}, {"key": "C", "value": "62,500", "is_correct": false}, {"key": "D", "value": "625,000", "is_correct": true}], "elimination_hints": ["A voltmeter has very high resistance, an ammeter has very low resistanceвЂ”the ratio should be a very large number.", "Options like 250 or 2,500 are too small for the ratio of a 10,000 О© voltmeter to a ~0.016 О© ammeter.", "Calculate each resistance separately: Rv = V/Ig and Ra в‰€ IgG/I, then find the ratio."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer has a coil of 200 turns, each of area 1.5 Г— 10вЃ»ВІ mВІ, and is placed in a magnetic field of 0.2 T. If the torsional constant of the spring is 1.2 NВ·m/rad, what is the current required to produce a deflection of 30В°?", "explanation": "At equilibrium, NIAB = kОё. Converting 30В° to radians: Оё = 30 Г— ПЂ/180 = ПЂ/6 rad в‰€ 0.5236 rad. So I = kОё/(NAB) = (1.2 Г— 0.5236)/(200 Г— 1.5 Г— 10вЃ»ВІ Г— 0.2) = 0.6283/(200 Г— 0.003) = 0.6283/0.6 = 1.047 A в‰€ 1.05 A.", "correct_answer": "D", "concept_tags": ["galvanometer deflection", "torque balance", "numerical problem"], "payload": {"question_id": "cuet-phy-mag-devices-18", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "0.52 A", "is_correct": false}, {"key": "B", "value": "2.10 A", "is_correct": false}, {"key": "C", "value": "0.63 A", "is_correct": false}, {"key": "D", "value": "1.05 A", "is_correct": true}], "elimination_hints": ["Remember to convert degrees to radians: 30В° = ПЂ/6 rad, not 30 directly.", "0.52 A would be the answer if you forgot to convert degrees to radians (using Оё = 30 without conversion would give a different error).", "I = kОё/(NAB). Compute NAB = 200 Г— 0.015 Г— 0.2 = 0.6. Then I = 1.2 Г— (ПЂ/6) / 0.6."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 50 О© and full-scale deflection current 2 mA is to be converted into an ammeter of range 0-10 A and a voltmeter of range 0-200 V. The ratio of shunt resistance to series resistance is:", "explanation": "For ammeter: S = Ig x G/(I - Ig) = 0.002 x 50/(10 - 0.002) в‰€ 0.1/9.998 в‰€ 0.01 О©. For voltmeter: R = V/Ig - G = 200/0.002 - 50 = 100000 - 50 = 99950 О©. Ratio S/R = 0.01/99950 в‰€ 1 x 10^-7. Alternatively, S/R = [Ig x G/(I - Ig)] / [V/Ig - G] в‰€ [Ig x G/I] / [V/Ig] = Ig^2 x G / (IV) = (0.002)^2 x 50 / (10 x 200) = 2 x 10^-7 / 2000 = 1 x 10^-7.", "correct_answer": "D", "concept_tags": ["ammeter-voltmeter-conversion", "shunt", "series-resistance", "ratio"], "payload": {"question_id": "cuet-phy-mag-devices-19", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 x 10^-3", "is_correct": false}, {"key": "B", "text": "1 x 10^-5", "is_correct": false}, {"key": "C", "text": "1 x 10^-6", "is_correct": false}, {"key": "D", "text": "1 x 10^-7", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would imply the shunt is only 1000 times smaller than the series resistance. Given the huge difference in conversion (ammeter needs ~0.01 О©, voltmeter needs ~100000 О©), the ratio should be much smaller.", "misconception": "Rough estimation without proper calculation"}, {"option_key": "B", "hint": "Verify your calculation: S в‰€ 0.01 О© and R в‰€ 99950 О©. The ratio 0.01/99950 is approximately 10^-7, not 10^-5.", "misconception": "Arithmetic error in the order of magnitude"}, {"option_key": "C", "hint": "Close but off by a factor of 10. Carefully recalculate: S/R = 0.01/99950 в‰€ 1.0 x 10^-7.", "misconception": "Small arithmetic or rounding error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton is accelerated in a cyclotron with magnetic field 1.5 T. The radius of the dees is 0.5 m. The maximum kinetic energy gained by the proton is approximately (mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C):", "explanation": "Maximum KE = q^2B^2R^2/(2m). Substituting: KE = (1.6 x 10^-19)^2 x (1.5)^2 x (0.5)^2 / (2 x 1.67 x 10^-27) = (2.56 x 10^-38) x 2.25 x 0.25 / (3.34 x 10^-27) = (2.56 x 10^-38 x 0.5625) / (3.34 x 10^-27) = 1.44 x 10^-38 / 3.34 x 10^-27 = 4.31 x 10^-12 J. Converting to MeV: 4.31 x 10^-12 / 1.6 x 10^-13 в‰€ 26.9 MeV в‰€ 27 MeV.", "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton", "numerical-calculation"], "payload": {"question_id": "cuet-phy-mag-devices-20", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "7 MeV", "is_correct": false}, {"key": "B", "text": "14 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "54 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "7 MeV is approximately 1/4 of the correct answer. Check if you used R = 0.25 m instead of 0.5 m, or missed squaring one of the terms.", "misconception": "Using R instead of R^2 in the kinetic energy formula"}, {"option_key": "B", "hint": "14 MeV is half the correct answer. Ensure you have squared both q and B correctly in q^2B^2R^2/(2m).", "misconception": "Forgetting to square one of the quantities"}, {"option_key": "D", "hint": "54 MeV is double the correct answer. Check that you included the factor of 2 in the denominator of KE = q^2B^2R^2/(2m).", "misconception": "Forgetting the factor of 1/2 in the kinetic energy expression"}]}}]'::jsonb, 'deploy-2026-03-05-b02');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a moving coil galvanometer with a cylindrical soft iron core placed between the poles of a permanent magnet. What is the primary purpose of the cylindrical soft iron core?", "explanation": "The cylindrical soft iron core serves to make the magnetic field radial. When placed between concave-shaped pole pieces, the soft iron core ensures that the plane of the coil is always parallel to the magnetic field direction, regardless of the coil''s rotational position. This makes the deflecting torque П„ = NIAB sin 90В° = NIAB, ensuring a linear relationship between current and deflection throughout the range of motion.", "correct_answer": "D", "concept_tags": ["soft iron core", "radial field", "galvanometer construction"], "payload": {"question_id": "cuet-phy-mag-devices-21", "subtopic": "Galvanometer construction", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "To increase the electrical resistance of the coil", "is_correct": false}, {"key": "B", "value": "To provide a restoring torque to the coil", "is_correct": false}, {"key": "C", "value": "To increase the moment of inertia of the coil", "is_correct": false}, {"key": "D", "value": "To make the magnetic field radial and uniform", "is_correct": true}], "elimination_hints": ["The core is made of soft iron (a magnetic material), not a resistorвЂ”so it doesn''t affect electrical resistance.", "The restoring torque is provided by the suspension wire/spring, not the core.", "Increasing moment of inertia would slow the responseвЂ”this would be a disadvantage, not a purpose."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a galvanometer G of resistance 20 О© connected with a shunt resistance S in parallel. If the galvanometer gives full-scale deflection for 10 mA and the shunt carries 90 mA, what is the value of S?", "explanation": "Since the galvanometer and shunt are in parallel, the voltage across both is equal: Ig Г— G = Is Г— S. Here Ig = 10 mA, G = 20 О©, and Is = 90 mA. So S = (Ig Г— G)/Is = (10 Г— 20)/90 = 200/90 = 20/9 в‰€ 2.22 О©.", "correct_answer": "C", "concept_tags": ["shunt resistance", "ammeter conversion", "parallel circuit"], "payload": {"question_id": "cuet-phy-mag-devices-22", "subtopic": "shunt resistance", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "2 О©", "is_correct": false}, {"key": "B", "value": "0.22 О©", "is_correct": false}, {"key": "C", "value": "20/9 О©", "is_correct": true}, {"key": "D", "value": "9/20 О©", "is_correct": false}], "elimination_hints": ["Use the equal voltage condition: Ig Г— G = Is Г— S, so S = IgG/Is.", "S = (10 Г— 20)/90 = 200/90. Simplify: 200/90 = 20/9.", "Option D (9/20 О©) is the reciprocal of the correct answerвЂ”a common trap in fraction-based problems."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The circuit diagram shows a galvanometer G (resistance 100 О©, full-scale deflection current 1 mA) connected with a resistance R in series, and this combination is connected across a battery of emf 10 V. What value of R converts the galvanometer into a voltmeter of range 0вЂ“10 V?", "explanation": "To convert a galvanometer into a voltmeter of range V, a high resistance R is connected in series. Using V = Ig(G + R): 10 = 0.001 Г— (100 + R), so 100 + R = 10000, giving R = 9900 О© = 9.9 kО©. The high series resistance ensures very little current is drawn from the circuit being measured.", "correct_answer": "B", "concept_tags": ["voltmeter conversion", "series resistance", "galvanometer"], "payload": {"question_id": "cuet-phy-mag-devices-23", "subtopic": "conversion to voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "10,000 О©", "is_correct": false}, {"key": "B", "value": "9,900 О©", "is_correct": true}, {"key": "C", "value": "990 О©", "is_correct": false}, {"key": "D", "value": "99,900 О©", "is_correct": false}], "elimination_hints": ["R = V/Ig в€’ G. Don''t forget to subtract the galvanometer resistance G from the total resistance.", "Total resistance needed = V/Ig = 10/0.001 = 10,000 О©. Since G = 100 О©, R = 10,000 в€’ 100.", "990 О© would give a voltmeter range of only about 1.09 VвЂ”too low for a 10 V range."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram shows two galvanometers P and Q with identical coils (same N, A, B) but different spring constants. If kP = 2kQ, what is the ratio of their current sensitivities (ОёP/IP) : (ОёQ/IQ)?", "explanation": "Current sensitivity = Оё/I = NAB/k. Since N, A, and B are the same for both galvanometers, the current sensitivity is inversely proportional to k. (ОёP/IP)/(ОёQ/IQ) = kQ/kP = kQ/(2kQ) = 1/2. Therefore, the ratio is 1:2. Galvanometer Q is more sensitive because it has a smaller spring constant.", "correct_answer": "B", "concept_tags": ["current sensitivity", "spring constant", "comparison"], "payload": {"question_id": "cuet-phy-mag-devices-24", "subtopic": "current sensitivity", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "value": "2 : 1", "is_correct": false}, {"key": "B", "value": "1 : 2", "is_correct": true}, {"key": "C", "value": "1 : 1", "is_correct": false}, {"key": "D", "value": "4 : 1", "is_correct": false}], "elimination_hints": ["Current sensitivity = NAB/k. Higher k means lower sensitivity.", "Since kP = 2kQ, P has a stiffer springвЂ”so P should be LESS sensitive than Q.", "The ratio is inversely proportional to k values: (1/kP) : (1/kQ) = (1/2kQ) : (1/kQ) = 1 : 2."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): An ammeter is always connected in parallel with the circuit element through which current is to be measured.\nReason (R): An ammeter has very low resistance so that it does not significantly change the current in the circuit.", "explanation": "The assertion is false. An ammeter is always connected in series with the circuit element, not in parallel. If connected in parallel, its low resistance would create a short circuit. The reason is trueвЂ”an ammeter does have very low resistance to minimize its effect on the circuit current. Since the assertion is false but the reason is true, the answer is D.", "correct_answer": "D", "concept_tags": ["ammeter", "series connection", "low resistance"], "payload": {"question_id": "cuet-phy-mag-devices-25", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "value": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "value": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": true}], "elimination_hints": ["Think carefully: is an ammeter connected in series or parallel? A parallel connection with low resistance would short the element.", "The reason about low resistance is correctвЂ”ammeters must have low resistance to not alter the current being measured.", "Since the assertion contains a factual error (parallel instead of series), options A and B (which state A is true) can be eliminated."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Increasing the number of turns of the coil in a galvanometer increases current sensitivity but may not increase voltage sensitivity.\nReason (R): Voltage sensitivity equals current sensitivity divided by the resistance of the galvanometer, and increasing turns increases resistance.", "explanation": "Both the assertion and reason are true, and the reason correctly explains the assertion. Current sensitivity = NAB/k, which increases with N. However, voltage sensitivity = NAB/(kR). When N increases, the resistance R of the coil also increases (roughly proportionally). So voltage sensitivity = NAB/(kR) may not increase because the increase in N in the numerator is offset by the increase in R in the denominator. The reason correctly identifies this relationship.", "correct_answer": "A", "concept_tags": ["current sensitivity", "voltage sensitivity", "number of turns"], "payload": {"question_id": "cuet-phy-mag-devices-26", "subtopic": "voltage sensitivity", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "value": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["Check current sensitivity formula: Оё/I = NAB/k. Increasing N clearly increases this.", "Check voltage sensitivity formula: Оё/V = NAB/(kR). If N doubles and R also doubles, voltage sensitivity stays the same.", "The reason provides the exact mathematical relationship that explains why voltage sensitivity may not increaseвЂ”this makes R a correct explanation of A."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The cyclotron frequency does not depend on the speed of the charged particle. Reason (R): In a cyclotron, as the particle gains speed, the radius of its circular path increases proportionally, keeping the time period constant.", "explanation": "Both the Assertion and Reason are correct, and the Reason correctly explains the Assertion. The cyclotron frequency f = qB/(2ПЂm) is independent of speed. This is because when a particle gains energy and moves faster (v increases), it moves to a larger radius orbit (r = mv/(qB)), so r increases proportionally with v. Since T = 2ПЂr/v = 2ПЂm/(qB), the v cancels out, making the period constant. This is the fundamental principle that allows the cyclotron to use a fixed-frequency oscillating electric field.", "correct_answer": "A", "concept_tags": ["cyclotron-frequency", "radius-speed-relation", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-mag-devices-27", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly explains why the frequency is independent of speed: the increase in radius exactly compensates for the increase in speed, so the time per revolution stays constant. This is a causal explanation.", "misconception": "Not recognizing the causal connection between the radius-speed relationship and constant frequency"}, {"option_key": "C", "hint": "The Reason is factually correct. In a cyclotron, r = mv/(qB), so r is directly proportional to v. The circumference (2ПЂr) grows in proportion to v, keeping T = 2ПЂr/v constant.", "misconception": "Doubting the relationship between radius and speed"}, {"option_key": "D", "hint": "The Assertion is correct: from f = qB/(2ПЂm), the frequency clearly does not contain velocity v, confirming it is independent of speed.", "misconception": "Thinking cyclotron frequency depends on speed"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Increasing the number of turns in a moving coil galvanometer always increases both its current sensitivity and voltage sensitivity. Reason (R): Current sensitivity is NAB/k and voltage sensitivity is NAB/(kG), and increasing N increases the resistance G of the coil.", "explanation": "The Assertion is incorrect. While increasing N does increase current sensitivity (Is = NAB/k), it also increases the coil resistance G (since G is proportional to N for a given wire). Voltage sensitivity Vs = NAB/(kG) = Is/G. As N increases, both NAB/k and G increase, and the net effect on Vs depends on the relative rates. In fact, since G is proportional to N (longer wire), Vs = NAB/(kG) may remain roughly constant or even decrease. So increasing N does NOT always increase voltage sensitivity. The Reason is correct: it correctly states both formulas and that increasing N increases G.", "correct_answer": "D", "concept_tags": ["current-sensitivity", "voltage-sensitivity", "number-of-turns", "galvanometer-design"], "payload": {"question_id": "cuet-phy-mag-devices-28", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion claims increasing N always increases both sensitivities. But since G also increases with N, voltage sensitivity Vs = NAB/(kG) may not increase. The Assertion is therefore incorrect.", "misconception": "Ignoring the effect of increased resistance when adding more turns"}, {"option_key": "B", "hint": "Since the Assertion is incorrect (voltage sensitivity does not necessarily increase with N), options involving ''A is correct'' cannot be right.", "misconception": "Not analyzing the voltage sensitivity formula carefully"}, {"option_key": "C", "hint": "The Reason correctly states the formulas and the fact that G increases with N. This is physically accurate since more turns mean longer wire and greater resistance.", "misconception": "Thinking the Reason is wrong about resistance increasing with turns"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Cyclotron frequency\n(Q) Shunt resistance for ammeter\n(R) Series resistance for voltmeter\n(S) Current sensitivity of galvanometer\n\nColumn II:\n(1) NAB/k\n(2) V/Ig - G\n(3) qB/(2ПЂm)\n(4) IgВ·G/(I - Ig)", "explanation": "P-3: Cyclotron frequency f = qB/(2ПЂm). Q-4: Shunt resistance S = IgВ·G/(I - Ig) for converting galvanometer to ammeter. R-2: Series resistance R = V/Ig - G for converting galvanometer to voltmeter. S-1: Current sensitivity = NAB/k, which is the deflection per unit current in a galvanometer.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "ammeter-conversion", "voltmeter-conversion", "current-sensitivity", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-devices-29", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "P-3, Q-2, R-4, S-1", "is_correct": false}, {"key": "B", "text": "P-3, Q-4, R-2, S-1", "is_correct": true}, {"key": "C", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "D", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Q and R. The shunt resistance formula contains IgВ·G/(I - Ig) which is (4), while the series resistance formula is V/Ig - G which is (2). So Q matches 4, not 2.", "misconception": "Swapping the ammeter and voltmeter conversion formulas"}, {"option_key": "C", "hint": "P-4 would match cyclotron frequency to the shunt formula, which is dimensionally inconsistent. Cyclotron frequency has units of Hz = 1/s, while IgВ·G/(I-Ig) has units of О©.", "misconception": "Not checking dimensional consistency of the formulas"}, {"option_key": "D", "hint": "P-1 matches cyclotron frequency with NAB/k, which is the current sensitivity formula. Cyclotron frequency f = qB/(2ПЂm) matches with (3).", "misconception": "Confusing cyclotron frequency with galvanometer sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field inside a long solenoid\n(Q) Magnetic field of a toroid (inside)\n(R) Cyclotron maximum KE\n(S) Deflecting torque in a galvanometer\n\nColumn II:\n(1) NIAB\n(2) Ојв‚ЂnI (n = turns per unit length)\n(3) qВІBВІRВІ/(2m)\n(4) Ојв‚ЂNI/(2ПЂr)", "explanation": "P-2: The magnetic field inside a long solenoid is B = Ојв‚ЂnI, where n is the number of turns per unit length. Q-4: Inside a toroid, B = Ојв‚ЂNI/(2ПЂr), where N is total turns and r is the radius of the toroidal path. R-3: Maximum kinetic energy from a cyclotron is qВІBВІRВІ/(2m). S-1: The deflecting torque on the coil in a galvanometer is П„ = NIAB.", "correct_answer": "A", "concept_tags": ["solenoid", "toroid", "cyclotron-energy", "galvanometer-torque", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-devices-30", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-4, R-3, S-1", "is_correct": true}, {"key": "B", "text": "P-4, Q-2, R-3, S-1", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": false}, {"key": "D", "text": "P-2, Q-1, R-3, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This swaps P and Q. The solenoid field B = Ојв‚ЂnI uses turns per unit length (n), while the toroid field B = Ојв‚ЂNI/(2ПЂr) uses total turns N and has r in the denominator.", "misconception": "Confusing the solenoid and toroid magnetic field formulas"}, {"option_key": "C", "hint": "R-1 would match cyclotron KE with NIAB (torque). The cyclotron KE expression qВІBВІRВІ/(2m) is (3), and NIAB is the galvanometer torque (1).", "misconception": "Swapping the cyclotron energy and galvanometer torque expressions"}, {"option_key": "D", "hint": "Q-1 would match toroid field with NIAB, which is the torque expression for a galvanometer. The toroid field is Ојв‚ЂNI/(2ПЂr), which is (4).", "misconception": "Not distinguishing between the torque formula and the toroid field formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The figure of merit of a galvanometer is defined as the current required to produce a unit deflection in the galvanometer.", "explanation": "This statement is TRUE. The figure of merit of a galvanometer is defined as the current required to produce one unit (one division) of deflection. Mathematically, figure of merit = k/(NAB), where k is the torsional constant, N is the number of turns, A is the area, and B is the magnetic field. A smaller figure of merit indicates a more sensitive galvanometer.", "correct_answer": "A", "concept_tags": ["figure of merit", "galvanometer sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-31", "subtopic": "figure of merit", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "True", "is_correct": true}, {"key": "B", "value": "False", "is_correct": false}, {"key": "C", "value": "---", "is_correct": false}, {"key": "D", "value": "---", "is_correct": false}], "elimination_hints": ["Recall: figure of merit = I/Оё = k/(NAB). It represents current per unit deflection.", "This is a standard textbook definitionвЂ”figure of merit is the reciprocal of current sensitivity."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside a solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This statement is TRUE. Inside a long solenoid (ideal case), the magnetic field is uniform in both magnitude and direction. The field lines run parallel to the axis of the solenoid. This can be derived using Ampere''s law, which gives B = Ојв‚ЂnI inside the solenoid (where n = N/L is the number of turns per unit length). Outside the solenoid, the field is approximately zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-magnetic-field", "field-direction"], "payload": {"question_id": "cuet-phy-mag-devices-32", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The field inside an ideal long solenoid is indeed uniform and axial. This is a standard result from Ampere''s law applied to a rectangular Amperian loop.", "misconception": "Confusing solenoid field with that of a bar magnet, where the field is non-uniform"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "An ideal voltmeter has zero resistance so that it does not draw any current from the circuit.", "explanation": "This statement is FALSE. An ideal voltmeter has infinite resistance (not zero resistance) so that it draws zero current from the circuit. Zero resistance is the characteristic of an ideal ammeter, not a voltmeter. A voltmeter with zero resistance would short-circuit the component across which it is connected.", "correct_answer": "B", "concept_tags": ["ideal voltmeter", "infinite resistance"], "payload": {"question_id": "cuet-phy-mag-devices-33", "subtopic": "conversion to voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "True", "is_correct": false}, {"key": "B", "value": "False", "is_correct": true}, {"key": "C", "value": "---", "is_correct": false}, {"key": "D", "value": "---", "is_correct": false}], "elimination_hints": ["Think about what happens if a voltmeter with zero resistance is connected in parallelвЂ”it would short-circuit the component.", "Zero resistance is the property of an ideal ammeter, not a voltmeter.", "For no current to flow through the voltmeter, its resistance must be as high as possibleвЂ”ideally infinite."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A cyclotron can be used to accelerate electrons to high energies efficiently.", "explanation": "This statement is FALSE. A cyclotron cannot efficiently accelerate electrons because electrons have very small mass (9.1 x 10^-31 kg). Due to their low mass, electrons quickly reach relativistic speeds, at which point their mass increases significantly (relativistic mass increase). This causes the cyclotron frequency f = qB/(2ПЂm) to decrease, and the particles go out of synchronization with the fixed-frequency oscillating electric field. This is a well-known limitation of the cyclotron.", "correct_answer": "B", "concept_tags": ["cyclotron", "electrons", "relativistic-effects", "limitation"], "payload": {"question_id": "cuet-phy-mag-devices-34", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small rest mass, so they reach relativistic speeds at relatively low energies. At relativistic speeds, the effective mass increases, changing the cyclotron frequency and causing loss of synchronization.", "misconception": "Thinking the cyclotron works for all charged particles without considering relativistic effects"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, a ________ resistance is connected in ________ with the galvanometer.", "explanation": "To convert a galvanometer into a voltmeter, a high resistance is connected in series with it. The high series resistance ensures that the voltmeter draws negligible current from the circuit, thereby not disturbing the potential difference being measured. The total resistance of the voltmeter becomes R + G, where R >> G.", "correct_answer": "A", "concept_tags": ["voltmeter conversion", "series resistance"], "payload": {"question_id": "cuet-phy-mag-devices-35", "subtopic": "conversion to voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "high; series", "is_correct": true}, {"key": "B", "value": "low; series", "is_correct": false}, {"key": "C", "value": "high; parallel", "is_correct": false}, {"key": "D", "value": "low; parallel", "is_correct": false}], "elimination_hints": ["A voltmeter must have high resistance to avoid drawing significant currentвЂ”this eliminates options with ''low'' resistance.", "A voltmeter measures potential difference across a component, so it must be connected in parallel with the component, but the internal conversion uses series connection.", "Low resistance in parallel describes an ammeter conversion (shunt), not a voltmeter conversion."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "In a moving coil galvanometer, a radial magnetic field is produced by using concave-shaped pole pieces and a _____ placed inside the coil.", "explanation": "A soft iron core is placed inside the coil of a moving coil galvanometer. The soft iron core, along with the concave-shaped (cylindrical) pole pieces of the permanent magnet, creates a radial magnetic field. In a radial field, the plane of the coil is always parallel to the magnetic field direction, so the torque П„ = NIAB sin(90В°) = NIAB for all angular positions. This ensures a linear relationship between the current and the deflection angle (Оё в€ќ I).", "correct_answer": "C", "concept_tags": ["moving-coil-galvanometer", "radial-field", "soft-iron-core", "construction"], "payload": {"question_id": "cuet-phy-mag-devices-36", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Hard iron core", "is_correct": false}, {"key": "B", "text": "Copper cylinder", "is_correct": false}, {"key": "C", "text": "Soft iron core", "is_correct": true}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Hard iron retains magnetism (used for permanent magnets) and is not suitable for the core. Soft iron is used because it has high permeability, low retentivity, and strengthens the radial field without permanent magnetization.", "misconception": "Confusing soft iron (high permeability, low retentivity) with hard iron (permanent magnets)"}, {"option_key": "B", "hint": "A copper cylinder is not used as the core. Copper is non-magnetic and would not help in creating a radial magnetic field. Soft iron''s high magnetic permeability is essential for concentrating field lines.", "misconception": "Confusing copper damping mechanism with the iron core"}, {"option_key": "D", "hint": "The permanent magnet provides the external magnetic field and is located outside the coil (as pole pieces). The core inside the coil is soft iron, which helps make this external field radial.", "misconception": "Confusing the location and role of the permanent magnet with the core"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "If the student first converts the galvanometer into an ammeter of range 0вЂ“2 A and then uses the same galvanometer (after removing the shunt) to make a voltmeter of range 0вЂ“50 V, what is the difference between the high resistance needed for the voltmeter and the shunt resistance needed for the ammeter?", "explanation": "For the ammeter: S = IgG/(I в€’ Ig) = (0.004 Г— 25)/(2 в€’ 0.004) = 0.1/1.996 в‰€ 0.05 О©. For the voltmeter: R = V/Ig в€’ G = 50/0.004 в€’ 25 = 12,500 в€’ 25 = 12,475 О©. Difference = 12,475 в€’ 0.05 = 12,474.95 в‰€ 12,475 О©. The voltmeter resistance is overwhelmingly larger than the shunt resistance.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "voltmeter conversion", "shunt resistance", "series resistance"], "payload": {"question_id": "cuet-phy-mag-devices-37", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "12,500 О©", "is_correct": false}, {"key": "B", "value": "12,450 О©", "is_correct": false}, {"key": "C", "value": "12,475 О© (approx.)", "is_correct": true}, {"key": "D", "value": "12,525 О©", "is_correct": false}], "elimination_hints": ["The shunt resistance is very small (~0.05 О©), so the difference is approximately equal to the voltmeter''s series resistance itself.", "Voltmeter series resistance R = V/Ig в€’ G = 12,500 в€’ 25 = 12,475 О©. The shunt is negligible in comparison.", "12,500 О© would be the answer if G were zeroвЂ”but we must subtract G = 25 О© from the total."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A medical research lab uses a cyclotron to produce radioactive isotopes for PET (Positron Emission Tomography) scans. The cyclotron accelerates protons using a magnetic field of 2.0 T. The protons are extracted when they reach a radius of 0.4 m from the centre. If the cyclotron''s oscillating electric field operates at a fixed frequency, what is the frequency of the oscillating electric field, and what is the kinetic energy of the extracted protons? (Given: mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C)", "explanation": "The cyclotron frequency f = qB/(2ПЂm) = (1.6 x 10^-19 x 2.0)/(2ПЂ x 1.67 x 10^-27) = 3.2 x 10^-19 / (1.049 x 10^-26) = 3.05 x 10^7 Hz в‰€ 30.5 MHz. The maximum kinetic energy KE = qВІBВІRВІ/(2m) = (1.6 x 10^-19)ВІ x (2.0)ВІ x (0.4)ВІ / (2 x 1.67 x 10^-27) = (2.56 x 10^-38 x 4 x 0.16) / (3.34 x 10^-27) = 1.638 x 10^-38 / 3.34 x 10^-27 = 4.9 x 10^-12 J. Converting: 4.9 x 10^-12 / 1.6 x 10^-13 в‰€ 30.6 MeV. So the frequency is approximately 30.5 MHz and KE is approximately 30.6 MeV.", "correct_answer": "B", "concept_tags": ["cyclotron", "frequency", "kinetic-energy", "PET-scan", "medical-application", "numerical"], "payload": {"question_id": "cuet-phy-mag-devices-38", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "Frequency в‰€ 15.2 MHz, KE в‰€ 15 MeV", "is_correct": false}, {"key": "B", "text": "Frequency в‰€ 30.5 MHz, KE в‰€ 30.6 MeV", "is_correct": true}, {"key": "C", "text": "Frequency в‰€ 30.5 MHz, KE в‰€ 61 MeV", "is_correct": false}, {"key": "D", "text": "Frequency в‰€ 61 MHz, KE в‰€ 30.6 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "15.2 MHz is half the correct frequency. Check your calculation: f = qB/(2ПЂm). With B = 2.0 T, the numerator is qB = 3.2 x 10^-19, not 1.6 x 10^-19. Ensure you use B = 2.0 T, not 1.0 T.", "misconception": "Using B = 1.0 T instead of 2.0 T in the frequency formula"}, {"option_key": "C", "hint": "The frequency is correct at 30.5 MHz, but 61 MeV is double the actual KE. Verify the factor of 2 in the denominator: KE = qВІBВІRВІ/(2m), not qВІBВІRВІ/m.", "misconception": "Forgetting the factor of 2 in the kinetic energy denominator"}, {"option_key": "D", "hint": "61 MHz is double the correct frequency. The formula is f = qB/(2ПЂm), and 2ПЂ в‰€ 6.28, not ПЂ в‰€ 3.14. Using ПЂ instead of 2ПЂ would give the wrong answer.", "misconception": "Using ПЂ instead of 2ПЂ in the cyclotron frequency formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following steps in the correct logical sequence for converting a galvanometer into an ammeter:", "explanation": "The correct sequence is: First, determine the galvanometer parameters Ig and G (step 2). Then, identify the desired ammeter range I (step 4). Next, use these values to calculate the required shunt resistance S = IgG/(I в€’ Ig) (step 1). Finally, physically connect the shunt in parallel with the galvanometer (step 3). This sequence follows the logical flow from characterization to design to implementation.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "shunt resistance", "logical sequence"], "payload": {"question_id": "cuet-phy-mag-devices-39", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "1, 2, 3, 4", "is_correct": false}, {"key": "B", "value": "4, 2, 1, 3", "is_correct": false}, {"key": "C", "value": "2, 4, 1, 3", "is_correct": true}, {"key": "D", "value": "2, 1, 4, 3", "is_correct": false}], "elimination_hints": ["You must know the galvanometer''s properties (Ig, G) before anything elseвЂ”step 2 comes first.", "You cannot calculate the shunt (step 1) without knowing the desired range (step 4)вЂ”so step 4 must come before step 1.", "Physical connection (step 3) is always the last stepвЂ”it comes after all calculations are done."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following events in the correct sequence that occurs when a current is passed through a moving coil galvanometer:", "explanation": "The correct sequence of events is: First, current flows through the coil in the radial magnetic field (step 3). This creates a deflecting torque on the coil (step 2, П„ = NIAB). The coil then rotates and continues until the deflecting torque is balanced by the restoring torque of the spring (step 4, NIAB = kОё). Finally, the pointer shows the deflection on the scale (step 1). This follows the cause-and-effect chain from electrical input to mechanical output.", "correct_answer": "A", "concept_tags": ["galvanometer working", "deflecting torque", "restoring torque"], "payload": {"question_id": "cuet-phy-mag-devices-40", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "3, 2, 4, 1", "is_correct": true}, {"key": "B", "value": "2, 3, 1, 4", "is_correct": false}, {"key": "C", "value": "3, 2, 1, 4", "is_correct": false}, {"key": "D", "value": "2, 3, 4, 1", "is_correct": false}], "elimination_hints": ["The process starts with current flowing through the coilвЂ”this is the input, so step 3 comes first.", "The pointer reading (step 1) is the final outputвЂ”it must come last.", "Torque (step 2) is caused by the current (step 3), and the coil must rotate and reach equilibrium (step 4) before the reading is taken (step 1)."]}}]'::jsonb, 'deploy-2026-03-05-b02');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following materials is an example of a non-ohmic conductor?", "explanation": "A semiconductor diode (p-n junction diode) is a non-ohmic conductor because its V-I characteristic is non-linear; the current through it does not vary linearly with the applied voltage. Copper, aluminium, and silver are ohmic conductors that obey Ohm''s law at constant temperature.", "correct_answer": "C", "concept_tags": ["ohms-law", "non-ohmic-conductor", "V-I-characteristics"], "payload": {"question_id": "cuet-phy-current-ohm-01", "subtopic": "V-I Characteristics", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "Copper wire", "is_correct": false}, {"key": "B", "text": "Aluminium wire", "is_correct": false}, {"key": "C", "text": "Semiconductor diode", "is_correct": true}, {"key": "D", "text": "Silver wire", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Copper is a metal that obeys Ohm''s law at constant temperature, producing a linear V-I graph.", "misconception": "Thinking all conductors are non-ohmic"}, {"option_key": "B", "hint": "Aluminium, like copper, is a metallic conductor that follows Ohm''s law under constant physical conditions.", "misconception": null}, {"option_key": "D", "hint": "Silver is an excellent metallic conductor that follows Ohm''s law. It has the highest electrical conductivity among metals.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electrical conductivity is:", "explanation": "Conductivity sigma = 1/rho, where rho has units of ohm-metre (О©В·m). Therefore, conductivity has units of (О©В·m)вЃ»В№ = О©вЃ»В№mвЃ»В№, which can also be written as S/m (siemens per metre) or mho/m.", "correct_answer": "A", "concept_tags": ["conductivity", "SI-units", "resistivity"], "payload": {"question_id": "cuet-phy-current-ohm-02", "subtopic": "Conductivity", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "О©вЃ»В№mвЃ»В№", "is_correct": true}, {"key": "B", "text": "О©В·m", "is_correct": false}, {"key": "C", "text": "О©вЃ»В№m", "is_correct": false}, {"key": "D", "text": "О©В·mвЃ»В№", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "О©В·m is the unit of resistivity, not conductivity. Conductivity is the reciprocal of resistivity.", "misconception": "Confusing the unit of resistivity with conductivity"}, {"option_key": "C", "hint": "О©вЃ»В№m would be obtained only if resistivity had units of О©/m, which is incorrect.", "misconception": "Incorrect dimensional analysis of conductivity"}, {"option_key": "D", "hint": "О©В·mвЃ»В№ does not correctly represent the reciprocal of О©В·m. The reciprocal of О©В·m is О©вЃ»В№mвЃ»В№.", "misconception": "Only inverting one part of the compound unit"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Ohm''s law, the current flowing through a conductor is:", "explanation": "Ohm''s law states that V = IR, which means I = V/R. The current through a conductor is directly proportional to the potential difference across its ends and inversely proportional to its resistance, provided physical conditions like temperature remain constant.", "correct_answer": "B", "concept_tags": ["ohms-law", "current", "voltage", "resistance"], "payload": {"question_id": "cuet-phy-current-ohm-03", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "Directly proportional to resistance", "is_correct": false}, {"key": "B", "text": "Directly proportional to potential difference and inversely proportional to resistance", "is_correct": true}, {"key": "C", "text": "Inversely proportional to potential difference", "is_correct": false}, {"key": "D", "text": "Independent of potential difference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If current were directly proportional to resistance, increasing resistance would increase current, which contradicts Ohm''s law (I = V/R).", "misconception": "Confusing direct and inverse proportionality with resistance"}, {"option_key": "C", "hint": "Current is directly (not inversely) proportional to potential difference. Doubling V doubles I when R is constant.", "misconception": "Reversing the proportionality relationship with voltage"}, {"option_key": "D", "hint": "Current depends on potential difference; without a potential difference, no current flows through the conductor.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electrical resistivity is:", "explanation": "Resistivity ПЃ is defined by R = ПЃl/A, so ПЃ = RA/l. The unit of resistance is ohm (О©), area is mВІ, and length is m. Therefore, the unit of resistivity is О©В·mВІ / m = О©В·m.", "correct_answer": "C", "concept_tags": ["resistivity", "SI-units", "resistance"], "payload": {"question_id": "cuet-phy-current-ohm-04", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "О©/m", "is_correct": false}, {"key": "B", "text": "О©/mВІ", "is_correct": false}, {"key": "C", "text": "О©В·m", "is_correct": true}, {"key": "D", "text": "О©В·mВІ", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "О©/m would imply resistivity decreases with length, but from ПЃ = RA/l the correct dimensional analysis gives О©В·m.", "misconception": "Incorrectly dividing by length instead of multiplying"}, {"option_key": "B", "hint": "О©/mВІ does not follow from ПЃ = RA/l. The area appears in the numerator, not the denominator of ПЃ.", "misconception": null}, {"option_key": "D", "hint": "О©В·mВІ has an extra power of length. Dimensional analysis of ПЃ = RA/l gives О©В·m, not О©В·mВІ.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The drift velocity of free electrons in a conductor is of the order of:", "explanation": "The drift velocity of electrons in a metallic conductor carrying typical current is very small, of the order of 10вЃ»вЃґ m/s (about 0.1 mm/s). This is because although electrons move randomly at high thermal speeds (~10вЃ¶ m/s), the net drift due to the electric field is extremely slow.", "correct_answer": "A", "concept_tags": ["drift-velocity", "free-electrons", "conductor"], "payload": {"question_id": "cuet-phy-current-ohm-05", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "10вЃ»вЃґ m/s", "is_correct": true}, {"key": "B", "text": "10вЃ»В№вЃ° m/s", "is_correct": false}, {"key": "C", "text": "3 Г— 10вЃё m/s", "is_correct": false}, {"key": "D", "text": "10вЃ¶ m/s", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "10вЃ»В№вЃ° m/s is far too small even for drift velocity. Typical drift velocities are around 10вЃ»вЃґ m/s.", "misconception": null}, {"option_key": "C", "hint": "3 Г— 10вЃё m/s is the speed of light (speed of the electric signal), not the drift speed of electrons.", "misconception": "Confusing signal propagation speed with electron drift velocity"}, {"option_key": "D", "hint": "10вЃ¶ m/s is close to the thermal (random) speed of electrons, not their drift velocity in an applied field.", "misconception": "Confusing thermal velocity with drift velocity"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The reciprocal of resistivity is called:", "explanation": "Conductivity (Пѓ) is defined as the reciprocal of resistivity (ПЃ), i.e., Пѓ = 1/ПЃ. Its SI unit is О©вЃ»В№mвЃ»В№ or S/m (siemens per metre). It measures how easily a material allows current to flow through it.", "correct_answer": "D", "concept_tags": ["conductivity", "resistivity", "reciprocal"], "payload": {"question_id": "cuet-phy-current-ohm-06", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "Conductance", "is_correct": false}, {"key": "B", "text": "Susceptance", "is_correct": false}, {"key": "C", "text": "Reluctance", "is_correct": false}, {"key": "D", "text": "Conductivity", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Conductance (G = 1/R) is the reciprocal of resistance, not resistivity. Conductivity is the reciprocal of resistivity.", "misconception": "Confusing conductance (1/R) with conductivity (1/ПЃ)"}, {"option_key": "B", "hint": "Susceptance is the imaginary part of admittance in AC circuits and is unrelated to the reciprocal of resistivity.", "misconception": null}, {"option_key": "C", "hint": "Reluctance is a quantity in magnetic circuits (analogous to resistance) and has no relation to the reciprocal of resistivity.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A copper wire has a resistance of 8 О© at 20В°C. If the temperature coefficient of resistance for copper is 3.9 Г— 10вЃ»Ві per В°C, the resistance of the wire at 100В°C is approximately:", "explanation": "Using R_T = R_0(1 + alpha Г— О”T), where R_0 = 8 О©, alpha = 3.9 Г— 10вЃ»Ві per В°C, and О”T = 100 - 20 = 80В°C. R_100 = 8 Г— (1 + 3.9 Г— 10вЃ»Ві Г— 80) = 8 Г— (1 + 0.312) = 8 Г— 1.312 = 10.496 О© в‰€ 10.5 О©.", "correct_answer": "B", "concept_tags": ["temperature-coefficient", "resistance", "metals"], "payload": {"question_id": "cuet-phy-current-ohm-07", "subtopic": "Temperature Dependence of Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "8.31 О©", "is_correct": false}, {"key": "B", "text": "10.5 О©", "is_correct": true}, {"key": "C", "text": "12.8 О©", "is_correct": false}, {"key": "D", "text": "11.1 О©", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8.31 О© would result from using О”T = 10В°C instead of 80В°C; make sure you compute the full temperature difference.", "misconception": "Using incorrect temperature change"}, {"option_key": "C", "hint": "12.8 О© would result from using alpha = 0.006 per В°C, which is not the stated value for copper.", "misconception": "Using wrong temperature coefficient"}, {"option_key": "D", "hint": "11.1 О© does not match the correct calculation R = 8 Г— (1 + 3.9Г—10вЃ»Ві Г— 80) = 10.5 О©.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Three resistors of 6 О©, 3 О©, and 2 О© are connected in parallel. The equivalent resistance of the combination is:", "explanation": "For resistors in parallel: 1/R_eq = 1/Rв‚Ѓ + 1/Rв‚‚ + 1/Rв‚ѓ = 1/6 + 1/3 + 1/2 = 1/6 + 2/6 + 3/6 = 6/6 = 1. Therefore R_eq = 1 О©. The equivalent resistance in a parallel combination is always less than the smallest individual resistance.", "correct_answer": "D", "concept_tags": ["parallel-combination", "equivalent-resistance", "resistors"], "payload": {"question_id": "cuet-phy-current-ohm-08", "subtopic": "Series and Parallel Resistors", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "11 О©", "is_correct": false}, {"key": "B", "text": "2 О©", "is_correct": false}, {"key": "C", "text": "3 О©", "is_correct": false}, {"key": "D", "text": "1 О©", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "11 О© is the sum 6+3+2, which is the equivalent resistance for a series combination, not parallel.", "misconception": "Using series formula instead of parallel formula"}, {"option_key": "B", "hint": "2 О© is the smallest resistor, but the parallel equivalent must be less than the smallest individual resistance.", "misconception": "Thinking parallel resistance equals the smallest resistance"}, {"option_key": "C", "hint": "3 О© is one of the individual resistances and does not correspond to the parallel combination result.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the drift velocity of electrons in a conductor is doubled while the number density of free electrons remains the same, the current through the conductor:", "explanation": "Current I = nAv_d, where n is the number density, A is the cross-sectional area, and v_d is the drift velocity. If v_d is doubled and all other quantities remain constant, the current I also doubles. Current is directly proportional to drift velocity.", "correct_answer": "B", "concept_tags": ["drift-velocity", "current", "number-density"], "payload": {"question_id": "cuet-phy-current-ohm-09", "subtopic": "Drift Velocity", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "Remains the same", "is_correct": false}, {"key": "B", "text": "Gets doubled", "is_correct": true}, {"key": "C", "text": "Gets halved", "is_correct": false}, {"key": "D", "text": "Becomes four times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since I = nAv_d, changing v_d must change the current. It cannot remain the same.", "misconception": "Thinking current is independent of drift velocity"}, {"option_key": "C", "hint": "The relation is I = nAv_d (direct proportionality), so doubling v_d doubles I, not halves it.", "misconception": "Assuming inverse proportionality between current and drift velocity"}, {"option_key": "D", "hint": "I is directly proportional to v_d (not v_dВІ), so doubling v_d doubles I, not quadruples it.", "misconception": "Confusing linear and quadratic dependence"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a resistor colour code, the sequence of bands is yellow, violet, orange, and gold. The value of the resistance is:", "explanation": "In the colour code: Yellow = 4, Violet = 7, Orange = 10Ві (multiplier), Gold = В±5% tolerance. The resistance = 47 Г— 10Ві = 47,000 О© = 47 kО© with В±5% tolerance.", "correct_answer": "C", "concept_tags": ["colour-code", "resistor", "tolerance"], "payload": {"question_id": "cuet-phy-current-ohm-10", "subtopic": "Colour Code of Resistors", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "4.7 kО© В± 5%", "is_correct": false}, {"key": "B", "text": "470 О© В± 5%", "is_correct": false}, {"key": "C", "text": "47 kО© В± 5%", "is_correct": true}, {"key": "D", "text": "470 kО© В± 5%", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4.7 kО© would result from using orange as 10ВІ instead of 10Ві. Orange represents the multiplier 10Ві.", "misconception": "Misassigning the multiplier value for orange"}, {"option_key": "B", "hint": "470 О© corresponds to yellow-violet-brown (10В№ multiplier), not yellow-violet-orange (10Ві multiplier).", "misconception": "Confusing brown and orange multipliers"}, {"option_key": "D", "hint": "470 kО© would require a multiplier of 10вЃґ (yellow band), but the third band is orange (10Ві).", "misconception": "Using incorrect multiplier exponent"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A wire of resistance 12 О© is stretched uniformly until its length becomes three times the original length. The new resistance of the wire is:", "explanation": "When a wire is stretched, its volume remains constant: Aв‚Ѓlв‚Ѓ = Aв‚‚lв‚‚. If lв‚‚ = 3lв‚Ѓ, then Aв‚‚ = Aв‚Ѓ/3. Using R = ПЃl/A, the new resistance Rв‚‚ = ПЃ(3lв‚Ѓ)/(Aв‚Ѓ/3) = 9ПЃlв‚Ѓ/Aв‚Ѓ = 9Rв‚Ѓ = 9 Г— 12 = 108 О©. When length increases n times, resistance increases nВІ times.", "correct_answer": "D", "concept_tags": ["resistance", "stretching-wire", "resistivity", "volume-conservation"], "payload": {"question_id": "cuet-phy-current-ohm-11", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "36 О©", "is_correct": false}, {"key": "B", "text": "4 О©", "is_correct": false}, {"key": "C", "text": "48 О©", "is_correct": false}, {"key": "D", "text": "108 О©", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "36 О© = 3 Г— 12 would result if only the length change were considered without accounting for the decrease in cross-sectional area.", "misconception": "Forgetting that stretching also reduces the cross-sectional area"}, {"option_key": "B", "hint": "4 О© = 12/3 would result from incorrectly dividing by the stretch factor instead of multiplying by its square.", "misconception": "Thinking resistance decreases when wire is stretched"}, {"option_key": "C", "hint": "48 О© does not correspond to any correct application of R = ПЃl/A with volume conservation.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current density in a copper wire of cross-sectional area 2 Г— 10вЃ»вЃ¶ mВІ carrying a current of 4 A is:", "explanation": "Current density J = I/A = 4 / (2 Г— 10вЃ»вЃ¶) = 2 Г— 10вЃ¶ A/mВІ. Current density is a vector quantity that gives the amount of current flowing per unit cross-sectional area perpendicular to the flow direction.", "correct_answer": "B", "concept_tags": ["current-density", "cross-sectional-area", "current"], "payload": {"question_id": "cuet-phy-current-ohm-12", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "8 Г— 10вЃ»вЃ¶ A/mВІ", "is_correct": false}, {"key": "B", "text": "2 Г— 10вЃ¶ A/mВІ", "is_correct": true}, {"key": "C", "text": "2 Г— 10вЃ»вЃ¶ A/mВІ", "is_correct": false}, {"key": "D", "text": "8 Г— 10вЃ¶ A/mВІ", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8 Г— 10вЃ»вЃ¶ A/mВІ results from multiplying I and A instead of dividing. J = I/A, not I Г— A.", "misconception": "Multiplying current and area instead of dividing"}, {"option_key": "C", "hint": "2 Г— 10вЃ»вЃ¶ is the value of the area itself, not the current density. J = 4/(2Г—10вЃ»вЃ¶) = 2Г—10вЃ¶.", "misconception": null}, {"option_key": "D", "hint": "8 Г— 10вЃ¶ would result from incorrectly using J = I Г— A Г— some factor. The correct calculation gives 2 Г— 10вЃ¶.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A wire of resistance R is cut into 4 equal parts and all parts are connected in parallel. The equivalent resistance of the combination is:", "explanation": "When a wire of resistance R is cut into 4 equal parts, each part has resistance R/4. When four resistances each of R/4 are connected in parallel, the equivalent resistance is (R/4)/4 = R/16. In general, cutting a wire into n equal parts and connecting them in parallel gives R/nВІ.", "correct_answer": "A", "concept_tags": ["resistance", "parallel-combination", "equivalent-resistance"], "payload": {"question_id": "cuet-phy-current-ohm-13", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "R/16", "is_correct": true}, {"key": "B", "text": "R/4", "is_correct": false}, {"key": "C", "text": "4R", "is_correct": false}, {"key": "D", "text": "R/8", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R/4 is the resistance of each individual piece. Connecting them in parallel further reduces the total resistance to R/16.", "misconception": "Forgetting to calculate the parallel combination after cutting"}, {"option_key": "C", "hint": "4R would be the result of connecting four resistances of R in series, not parallel pieces of a cut wire.", "misconception": "Confusing series and parallel combinations"}, {"option_key": "D", "hint": "R/8 would result if only 2 pieces were connected in parallel (each R/4, giving R/8 for two in parallel), not all four.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mobility of charge carriers in a conductor is defined as:", "explanation": "Mobility (Ој) of a charge carrier is defined as the magnitude of drift velocity per unit electric field, i.e., Ој = vd/E. Its SI unit is mВІ/(VВ·s). Mobility indicates how quickly a charge carrier can move through a material under the influence of an electric field.", "correct_answer": "C", "concept_tags": ["mobility", "drift-velocity", "electric-field"], "payload": {"question_id": "cuet-phy-current-ohm-14", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "Drift velocity per unit current", "is_correct": false}, {"key": "B", "text": "Current density per unit electric field", "is_correct": false}, {"key": "C", "text": "Drift velocity per unit electric field", "is_correct": true}, {"key": "D", "text": "Electric field per unit drift velocity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Mobility relates drift velocity to electric field, not to current. Ој = vd/E, and current does not appear in the definition.", "misconception": null}, {"option_key": "B", "hint": "Current density per unit electric field gives conductivity (Пѓ = J/E), not mobility.", "misconception": "Confusing conductivity with mobility"}, {"option_key": "D", "hint": "E/vd is the inverse of mobility. Mobility is vd/E, not E/vd.", "misconception": "Inverting the definition of mobility"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two wires A and B of the same material have lengths in the ratio 1:2 and diameters in the ratio 2:1. The ratio of their resistances R_A : R_B is:", "explanation": "R = ПЃl/A = ПЃl/(ПЂdВІ/4). So R в€ќ l/dВІ. For wire A: R_A в€ќ 1/4 and for wire B: R_B в€ќ 2/1 = 2. Therefore R_A/R_B = (1/4)/2 = 1/8. Wire B has 8 times the resistance of wire A due to being longer and thinner.", "correct_answer": "A", "concept_tags": ["resistance", "length", "diameter", "cross-section"], "payload": {"question_id": "cuet-phy-current-ohm-15", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "1 : 8", "is_correct": true}, {"key": "B", "text": "1 : 4", "is_correct": false}, {"key": "C", "text": "1 : 2", "is_correct": false}, {"key": "D", "text": "2 : 1", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1:4 would result from using R в€ќ l/d instead of R в€ќ l/dВІ, ignoring that area depends on the square of the diameter.", "misconception": "Forgetting to square the diameter ratio in resistance calculation"}, {"option_key": "C", "hint": "1:2 only considers the length ratio and completely ignores the difference in diameters.", "misconception": "Ignoring the effect of cross-sectional area on resistance"}, {"option_key": "D", "hint": "2:1 reverses the ratio. Wire A has a larger cross-section and shorter length, so it has less resistance, not more.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a colour code of carbon resistors, a resistor has bands: brown, black, red, and gold. The value of the resistance is:", "explanation": "In the colour code, brown = 1, black = 0, red = multiplier 10ВІ = 100, and gold = В±5% tolerance. The resistance value = 10 Г— 100 = 1000 О© = 1 kО© with В±5% tolerance. The first two bands give the significant digits and the third band gives the multiplier.", "correct_answer": "D", "concept_tags": ["colour-code", "carbon-resistor", "resistance-value"], "payload": {"question_id": "cuet-phy-current-ohm-16", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "100 О© В± 5%", "is_correct": false}, {"key": "B", "text": "10 kО© В± 5%", "is_correct": false}, {"key": "C", "text": "1 kО© В± 10%", "is_correct": false}, {"key": "D", "text": "1 kО© В± 5%", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "100 О© would require the multiplier band to be brown (10В№), not red (10ВІ). The correct value is 10 Г— 10ВІ = 1000 О©.", "misconception": "Misreading the multiplier band"}, {"option_key": "B", "hint": "10 kО© = 10,000 О© would require the multiplier to be 10Ві (orange), not 10ВІ (red).", "misconception": null}, {"option_key": "C", "hint": "The tolerance for gold is В±5%, not В±10%. Silver gives В±10% tolerance.", "misconception": "Confusing gold (В±5%) with silver (В±10%) tolerance band"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of resistance 20 О© is bent into a complete circle. The effective resistance between two diametrically opposite points is:", "explanation": "When a wire of resistance 20 О© is bent into a circle, it forms two semicircular arcs. Each semicircular arc has resistance 20/2 = 10 О©. Between diametrically opposite points, these two 10 О© arcs are connected in parallel. R_eq = (10 Г— 10)/(10 + 10) = 100/20 = 5 О©.", "correct_answer": "A", "concept_tags": ["resistance", "parallel-combination", "circular-wire"], "payload": {"question_id": "cuet-phy-current-ohm-17", "subtopic": "Series and Parallel Resistors", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "5 О©", "is_correct": true}, {"key": "B", "text": "10 О©", "is_correct": false}, {"key": "C", "text": "20 О©", "is_correct": false}, {"key": "D", "text": "2.5 О©", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "10 О© is the resistance of one semicircular half alone. The two halves are in parallel, giving a smaller value.", "misconception": "Forgetting that the two halves are in parallel"}, {"option_key": "C", "hint": "20 О© is the total resistance of the entire wire. Bending into a circle and measuring across a diameter yields a parallel combination.", "misconception": "Using total wire resistance without considering the parallel paths"}, {"option_key": "D", "hint": "2.5 О© would result from assuming four equal segments in parallel, which does not apply to diametrically opposite points.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The relaxation time of free electrons in a metallic conductor is 2.5 Г— 10вЃ»В№вЃґ s. If the number density of free electrons is 8.5 Г— 10ВІвЃё mвЃ»Ві and the mass of an electron is 9.1 Г— 10вЃ»ВіВ№ kg, the resistivity of the conductor is approximately:", "explanation": "Resistivity rho = m/(neВІП„), where m = 9.1 Г— 10вЃ»ВіВ№ kg, n = 8.5 Г— 10ВІвЃё mвЃ»Ві, e = 1.6 Г— 10вЃ»В№вЃ№ C, П„ = 2.5 Г— 10вЃ»В№вЃґ s. rho = (9.1 Г— 10вЃ»ВіВ№)/((8.5 Г— 10ВІвЃё)(1.6 Г— 10вЃ»В№вЃ№)ВІ(2.5 Г— 10вЃ»В№вЃґ)) = (9.1 Г— 10вЃ»ВіВ№)/((8.5 Г— 10ВІвЃё)(2.56 Г— 10вЃ»ВівЃё)(2.5 Г— 10вЃ»В№вЃґ)) = (9.1 Г— 10вЃ»ВіВ№)/(5.44 Г— 10вЃ»ВІВі) в‰€ 1.67 Г— 10вЃ»вЃё О©В·m в‰€ 1.7 Г— 10вЃ»вЃё О©В·m.", "correct_answer": "D", "concept_tags": ["resistivity", "relaxation-time", "drift-velocity", "free-electrons"], "payload": {"question_id": "cuet-phy-current-ohm-18", "subtopic": "Resistivity", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "1.7 Г— 10вЃ»вЃ¶ О©В·m", "is_correct": false}, {"key": "B", "text": "1.7 Г— 10вЃ»вЃґ О©В·m", "is_correct": false}, {"key": "C", "text": "1.7 Г— 10вЃ»ВІ О©В·m", "is_correct": false}, {"key": "D", "text": "1.7 Г— 10вЃ»вЃё О©В·m", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1.7 Г— 10вЃ»вЃ¶ is 100 times too large. Check that eВІ = (1.6Г—10вЃ»В№вЃ№)ВІ = 2.56Г—10вЃ»ВівЃё is correctly used.", "misconception": "Error in computing eВІ exponent"}, {"option_key": "B", "hint": "1.7 Г— 10вЃ»вЃґ is far too large for a metallic conductor. Typical metals have resistivities of the order 10вЃ»вЃё О©В·m.", "misconception": "Major arithmetic error in exponent calculation"}, {"option_key": "C", "hint": "1.7 Г— 10вЃ»ВІ О©В·m is in the range of semiconductors, not metals. The given data corresponds to a metal.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A cylindrical conductor of length l and radius r has resistance R. If it is reshaped into a conductor of length 2l, what is the ratio of the new resistance to the original resistance?", "explanation": "Volume is conserved: ПЂrВІl = ПЂr''ВІ(2l), giving r''ВІ = rВІ/2. The new resistance R'' = ПЃ(2l)/(ПЂrВІ/2) = 4ПЃl/(ПЂrВІ) = 4R. Since resistance R = ПЃl/A, doubling length while conserving volume halves the area, making the new resistance 4 times the original.", "correct_answer": "C", "concept_tags": ["resistance", "reshaping-conductor", "volume-conservation"], "payload": {"question_id": "cuet-phy-current-ohm-19", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 1", "is_correct": false}, {"key": "B", "text": "2 : 1", "is_correct": false}, {"key": "C", "text": "4 : 1", "is_correct": true}, {"key": "D", "text": "8 : 1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1:1 would only be true if both length and area remain unchanged. Reshaping changes both dimensions.", "misconception": "Thinking reshaping does not change resistance"}, {"option_key": "B", "hint": "2:1 considers only the length doubling (R в€ќ l) but ignores the halving of cross-sectional area due to volume conservation.", "misconception": "Forgetting to account for area change when volume is conserved"}, {"option_key": "D", "hint": "8:1 would apply if length were tripled (R в€ќ nВІ), not doubled. For doubling, R'' = 2ВІ Г— R = 4R.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A copper wire of cross-sectional area 2 mmВІ carries a current of 10 A. If the number density of free electrons is 8 Г— 10ВІвЃё per mВі, the drift velocity of electrons is approximately:", "explanation": "Using I = nAevd, we get vd = I/(nAe) = 10/(8 Г— 10ВІвЃё Г— 2 Г— 10вЃ»вЃ¶ Г— 1.6 Г— 10вЃ»В№вЃ№) = 10/(8 Г— 2 Г— 1.6 Г— 10Ві) = 10/25600 в‰€ 3.9 Г— 10вЃ»вЃґ m/s в‰€ 0.4 mm/s. This demonstrates that despite large current, electron drift velocity is very small.", "correct_answer": "B", "concept_tags": ["drift-velocity", "current", "number-density", "electron-charge"], "payload": {"question_id": "cuet-phy-current-ohm-20", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "3.9 Г— 10вЃ»ВІ m/s", "is_correct": false}, {"key": "B", "text": "3.9 Г— 10вЃ»вЃґ m/s", "is_correct": true}, {"key": "C", "text": "3.9 Г— 10вЃ»вЃ¶ m/s", "is_correct": false}, {"key": "D", "text": "3.9 Г— 10вЃ»В№ m/s", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3.9 Г— 10вЃ»ВІ m/s is 100 times too large, likely from an error in unit conversion of the area (using mВІ instead of mmВІ).", "misconception": "Forgetting to convert mmВІ to mВІ"}, {"option_key": "C", "hint": "3.9 Г— 10вЃ»вЃ¶ m/s is 100 times too small, possibly from an extra factor error in the calculation.", "misconception": null}, {"option_key": "D", "hint": "3.9 Г— 10вЃ»В№ m/s is unrealistically large for drift velocity in a conductor. Typical drift velocities are of the order 10вЃ»вЃґ m/s.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b02');

